insert into public.questions (id, topic, source, q, opts, ans_idx, exp, category, category_icon, is_active)
values
(3704, 'ASA Classification', 'AI Practice Question', 'A patient with well-controlled hypertension and no functional limitation is classified as which ASA physical status?', '["ASA I","ASA II","ASA III","ASA IV"]'::jsonb, 1, 'ASA II describes a patient with mild systemic disease and no substantive functional limitation, such as well-controlled hypertension or diabetes.', 'Anaesthesia & Perioperative Care', '💉', true),
(3705, 'Preoperative Fasting', 'AI Practice Question', 'Standard preoperative fasting guidance for clear fluids before elective surgery is:', '["No restriction needed","2 hours","6 hours","12 hours"]'::jsonb, 1, 'Clear fluids may be taken up to 2 hours before elective surgery under modern fasting guidelines, reducing unnecessary dehydration without increasing aspiration risk.', 'Anaesthesia & Perioperative Care', '💉', true),
(3706, 'Preoperative Fasting', 'AI Practice Question', 'Minimum fasting time for a light meal before elective anaesthesia is generally:', '["1 hour","2 hours","6 hours","24 hours"]'::jsonb, 2, 'A light meal requires at least 6 hours of fasting to allow adequate gastric emptying and reduce aspiration risk during induction.', 'Anaesthesia & Perioperative Care', '💉', true),
(3707, 'Malignant Hyperthermia', 'AI Practice Question', 'Which agent is most commonly implicated in triggering malignant hyperthermia?', '["Propofol","Succinylcholine","Fentanyl","Midazolam"]'::jsonb, 1, 'Succinylcholine and volatile inhalational anaesthetics are the classic triggers of malignant hyperthermia, a hypermetabolic crisis in genetically susceptible patients.', 'Anaesthesia & Perioperative Care', '💉', true),
(3708, 'Malignant Hyperthermia', 'AI Practice Question', 'The definitive drug treatment for malignant hyperthermia is:', '["Dantrolene","Naloxone","Flumazenil","Neostigmine"]'::jsonb, 0, 'Dantrolene works by inhibiting calcium release from the sarcoplasmic reticulum, directly reversing the hypermetabolic muscle crisis of malignant hyperthermia.', 'Anaesthesia & Perioperative Care', '💉', true),
(3709, 'Stages of Anaesthesia', 'AI Practice Question', 'During Guedel''s stages of anaesthesia, surgical procedures are typically performed during:', '["Stage I (analgesia)","Stage II (excitement)","Stage III (surgical anaesthesia)","Stage IV (overdose)"]'::jsonb, 2, 'Stage III surgical anaesthesia is characterised by regular respiration and loss of reflexes, the stage in which surgery is safely performed.', 'Anaesthesia & Perioperative Care', '💉', true),
(3710, 'Airway Complications', 'AI Practice Question', 'Laryngospasm during emergence from anaesthesia is best initially managed by:', '["Immediate tracheostomy","Positive pressure ventilation with 100% oxygen and jaw thrust","Deepening anaesthesia with volatile agent only","Administering atropine"]'::jsonb, 1, 'First-line management of laryngospasm is applying continuous positive airway pressure with 100% oxygen via a tight-fitting mask along with jaw thrust; small-dose propofol or succinylcholine is reserved for refractory cases.', 'Anaesthesia & Perioperative Care', '💉', true),
(3711, 'Muscle Relaxant Reversal', 'AI Practice Question', 'Reversal of a non-depolarising neuromuscular blocker is commonly achieved with:', '["Succinylcholine","Neostigmine and glycopyrrolate","Dantrolene","Naloxone"]'::jsonb, 1, 'Neostigmine (an acetylcholinesterase inhibitor) combined with an antimuscarinic such as glycopyrrolate reverses non-depolarising neuromuscular blockade while limiting cholinergic side effects.', 'Anaesthesia & Perioperative Care', '💉', true),
(3712, 'Regional Anaesthesia', 'AI Practice Question', 'A key difference between spinal and epidural anaesthesia is that spinal anaesthesia:', '["Uses a much larger drug volume","Is injected into the subarachnoid space with faster onset","Cannot cause hypotension","Is always preferred for short procedures under 10 minutes"]'::jsonb, 1, 'Spinal anaesthesia delivers a small volume of local anaesthetic directly into the CSF-filled subarachnoid space, producing rapid, dense block, unlike the larger-volume epidural space injection used for epidurals.', 'Anaesthesia & Perioperative Care', '💉', true),
(3713, 'Regional Anaesthesia', 'AI Practice Question', 'Post-dural puncture headache is classically described as:', '["Worse when lying flat","Worse when sitting or standing, relieved by lying flat","Unrelated to patient position","Only occurring in general anaesthesia"]'::jsonb, 1, 'Post-dural puncture headache is a postural headache — worsened by sitting/standing and relieved by lying supine — due to ongoing CSF leak reducing intracranial pressure support.', 'Anaesthesia & Perioperative Care', '💉', true),
(3714, 'PACU Discharge', 'AI Practice Question', 'The Aldrete score is used to assess:', '["Pain severity","Readiness for discharge from the post-anaesthesia care unit","Depth of anaesthesia intraoperatively","Risk of malignant hyperthermia"]'::jsonb, 1, 'The Aldrete scoring system evaluates activity, respiration, circulation, consciousness, and oxygen saturation to determine a patient''s readiness for PACU discharge.', 'Anaesthesia & Perioperative Care', '💉', true),
(3715, 'PONV', 'AI Practice Question', 'A commonly used first-line antiemetic for postoperative nausea and vomiting prophylaxis is:', '["Ondansetron","Morphine","Succinylcholine","Atropine"]'::jsonb, 0, 'Ondansetron, a 5-HT3 receptor antagonist, is a standard first-line agent for prevention and treatment of postoperative nausea and vomiting.', 'Anaesthesia & Perioperative Care', '💉', true),
(3716, 'Perioperative Hypothermia', 'AI Practice Question', 'Unintended perioperative hypothermia increases the risk of:', '["Improved wound healing","Surgical site infection and coagulopathy","Faster drug metabolism","Decreased bleeding"]'::jsonb, 1, 'Hypothermia impairs platelet function and clotting enzyme activity (worsening bleeding) and reduces immune function, increasing surgical site infection risk.', 'Anaesthesia & Perioperative Care', '💉', true),
(3717, 'Rapid Sequence Induction', 'AI Practice Question', 'Rapid sequence induction is primarily indicated for patients:', '["Who are fasted for over 12 hours","At high risk of pulmonary aspiration","Undergoing elective minor surgery","With no comorbidities"]'::jsonb, 1, 'RSI minimises the time between loss of airway reflexes and securing the airway, protecting patients at high aspiration risk (e.g. full stomach, bowel obstruction, pregnancy) from regurgitation.', 'Anaesthesia & Perioperative Care', '💉', true),
(3718, 'Rapid Sequence Induction', 'AI Practice Question', 'Cricoid pressure (Sellick''s manoeuvre) during rapid sequence induction is applied to:', '["Improve laryngoscopic view only","Occlude the oesophagus and reduce risk of passive regurgitation","Prevent laryngospasm","Increase heart rate"]'::jsonb, 1, 'Cricoid pressure compresses the oesophagus against the cervical vertebrae, theoretically reducing the risk of passive regurgitation of gastric contents during induction.', 'Anaesthesia & Perioperative Care', '💉', true),
(3719, 'Local Anaesthetic Toxicity', 'AI Practice Question', 'Early signs of local anaesthetic systemic toxicity (LAST) include:', '["Perioral numbness, tinnitus, and metallic taste","Bradycardia only","Hyperthermia","Improved level of consciousness"]'::jsonb, 0, 'Early LAST symptoms are typically neurological — perioral/tongue numbness, tinnitus, metallic taste, and light-headedness — before progressing to seizures and cardiovascular collapse.', 'Anaesthesia & Perioperative Care', '💉', true),
(3720, 'Local Anaesthetic Toxicity', 'AI Practice Question', 'The specific antidote for severe local anaesthetic systemic toxicity is:', '["Naloxone","Intravenous lipid emulsion","Flumazenil","Dantrolene"]'::jsonb, 1, 'Intravenous lipid emulsion (''lipid rescue'') is used to treat severe LAST, thought to act by sequestering lipophilic local anaesthetic away from cardiac tissue.', 'Anaesthesia & Perioperative Care', '💉', true),
(3721, 'Depth of Anaesthesia Monitoring', 'AI Practice Question', 'Bispectral Index (BIS) monitoring is used intraoperatively to assess:', '["Blood pressure trends","Depth of anaesthesia/consciousness","Neuromuscular blockade","Core temperature"]'::jsonb, 1, 'BIS monitoring processes EEG signals into a numeric score reflecting depth of anaesthesia, helping reduce the risk of intraoperative awareness.', 'Anaesthesia & Perioperative Care', '💉', true),
(3722, 'Induction Agents', 'AI Practice Question', 'Propofol as an induction agent is characterised by:', '["Slow onset and long duration of action","Rapid onset, rapid recovery, and antiemetic properties","Causing hypertension in most patients","Being the treatment for malignant hyperthermia"]'::jsonb, 1, 'Propofol has a rapid onset and offset due to fast redistribution and metabolism, and it has mild antiemetic properties, making it popular for induction and maintenance.', 'Anaesthesia & Perioperative Care', '💉', true),
(3723, 'Succinylcholine', 'AI Practice Question', 'A recognised adverse effect of succinylcholine is:', '["Hypokalaemia","Transient hyperkalaemia and muscle fasciculations","Prolonged hypotension only","Bronchodilation"]'::jsonb, 1, 'Succinylcholine''s depolarising action causes fasciculations and a transient rise in serum potassium, which can be dangerous in patients with burns, crush injury, or neuromuscular disease.', 'Anaesthesia & Perioperative Care', '💉', true),
(3724, 'Airway Assessment', 'AI Practice Question', 'The Mallampati score is used preoperatively to assess:', '["Cardiac risk","Predicted difficulty of laryngoscopy/intubation","Renal function","Coagulation status"]'::jsonb, 1, 'The Mallampati classification grades visibility of oropharyngeal structures with the mouth open and tongue protruded, helping predict potential difficult intubation.', 'Anaesthesia & Perioperative Care', '💉', true),
(3725, 'Regional Anaesthesia Contraindications', 'AI Practice Question', 'A contraindication to neuraxial (spinal/epidural) anaesthesia is:', '["Mild anxiety","Coagulopathy or infection at the injection site","Stable vital signs","Patient preference for regional technique"]'::jsonb, 1, 'Coagulopathy risks epidural/spinal haematoma, and local infection risks introducing pathogens into the CSF or epidural space — both are recognised contraindications.', 'Anaesthesia & Perioperative Care', '💉', true),
(3726, 'Postoperative Shivering', 'AI Practice Question', 'Postoperative shivering is most commonly related to:', '["Intraoperative hypothermia","Hyperglycaemia","Excessive analgesia","Overhydration"]'::jsonb, 0, 'Shivering after anaesthesia is most often a thermoregulatory response to intraoperative heat loss and residual anaesthetic effects on thermoregulation.', 'Anaesthesia & Perioperative Care', '💉', true),
(3727, 'Emergence Delirium', 'AI Practice Question', 'Emergence delirium following general anaesthesia is characterised by:', '["Calm, oriented behaviour","Agitation, confusion, and thrashing shortly after waking","Prolonged unconsciousness","Normal cognitive function throughout"]'::jsonb, 1, 'Emergence delirium presents as acute agitation, disorientation, and thrashing in the immediate post-anaesthesia period, more common in children and after certain agents like sevoflurane.', 'Anaesthesia & Perioperative Care', '💉', true),
(3728, 'Epidural Complications', 'AI Practice Question', 'Hypotension following epidural anaesthesia is primarily caused by:', '["Direct cardiotoxicity of local anaesthetic","Sympathetic nervous system blockade causing vasodilation","Excessive fluid administration","Bradycardia from vagal stimulation only"]'::jsonb, 1, 'Epidural local anaesthetic blocks sympathetic fibres, causing vasodilation and venous pooling that reduces venous return and blood pressure.', 'Anaesthesia & Perioperative Care', '💉', true),
(3729, 'TIVA', 'AI Practice Question', 'Total intravenous anaesthesia (TIVA) refers to:', '["Anaesthesia maintained solely with intravenous agents, without inhalational anaesthetics","Anaesthesia using only regional blocks","A technique reserved for cardiac surgery only","Anaesthesia requiring no monitoring"]'::jsonb, 0, 'TIVA maintains anaesthesia using intravenous agents such as propofol (often via target-controlled infusion) instead of volatile inhalational anaesthetics.', 'Anaesthesia & Perioperative Care', '💉', true),
(3730, 'Cardiac Conduction', 'AI Practice Question', 'The normal cardiac electrical impulse originates in the:', '["AV node","Sinoatrial (SA) node","Bundle of His","Purkinje fibres"]'::jsonb, 1, 'The SA node, located in the right atrium, is the heart''s natural pacemaker and initiates the normal cardiac impulse.', 'Anatomy & Physiology', '🧬', true),
(3731, 'Cardiac Anatomy', 'AI Practice Question', 'The layer of the heart responsible for its pumping contraction is the:', '["Endocardium","Myocardium","Pericardium","Epicardium"]'::jsonb, 1, 'The myocardium is the thick muscular middle layer responsible for the heart''s contractile pumping action.', 'Anatomy & Physiology', '🧬', true),
(3732, 'Renal Physiology', 'AI Practice Question', 'Filtration of blood in the nephron primarily occurs at the:', '["Loop of Henle","Glomerulus","Distal convoluted tubule","Collecting duct"]'::jsonb, 1, 'The glomerulus, a capillary tuft within Bowman''s capsule, is the site of filtration of plasma into the nephron.', 'Anatomy & Physiology', '🧬', true),
(3733, 'CNS Anatomy', 'AI Practice Question', 'Which meningeal layer lies closest to the brain surface?', '["Dura mater","Arachnoid mater","Pia mater","Periosteum"]'::jsonb, 2, 'The pia mater is the innermost, delicate meningeal layer that closely adheres to the surface of the brain and spinal cord.', 'Anatomy & Physiology', '🧬', true),
(3734, 'Coagulation', 'AI Practice Question', 'The extrinsic coagulation pathway is activated by:', '["Contact with collagen","Tissue factor released from damaged tissue","Platelet aggregation alone","Fibrinolysis"]'::jsonb, 1, 'The extrinsic pathway is triggered when tissue factor (thromboplastin) is released from damaged endothelium/tissue, initiating clotting via factor VII.', 'Anatomy & Physiology', '🧬', true),
(3735, 'Endocrine Anatomy', 'AI Practice Question', 'Aldosterone is secreted from which zone of the adrenal cortex?', '["Zona glomerulosa","Zona fasciculata","Zona reticularis","Adrenal medulla"]'::jsonb, 0, 'The zona glomerulosa, the outermost adrenal cortex layer, produces mineralocorticoids such as aldosterone.', 'Anatomy & Physiology', '🧬', true),
(3736, 'Autonomic Nervous System', 'AI Practice Question', 'Stimulation of the sympathetic nervous system typically causes which cardiac effect?', '["Decreased heart rate and contractility","Increased heart rate and contractility","No cardiac effect","Complete heart block"]'::jsonb, 1, 'Sympathetic stimulation releases catecholamines that increase heart rate (chronotropy) and contractility (inotropy) via beta-1 receptors.', 'Anatomy & Physiology', '🧬', true),
(3737, 'Oxygen-Haemoglobin Curve', 'AI Practice Question', 'A rightward shift of the oxygen-haemoglobin dissociation curve is caused by:', '["Decreased temperature","Increased 2,3-DPG, CO2, and temperature","Decreased CO2","Alkalosis"]'::jsonb, 1, 'Increased temperature, CO2, hydrogen ion concentration (acidosis), and 2,3-DPG shift the curve right, reducing haemoglobin''s oxygen affinity and favouring oxygen release to tissues.', 'Anatomy & Physiology', '🧬', true),
(3738, 'Starling Forces', 'AI Practice Question', 'Fluid movement out of capillaries into the interstitium is favoured by:', '["High capillary hydrostatic pressure and low plasma oncotic pressure","Low capillary hydrostatic pressure only","High plasma oncotic pressure only","Equal hydrostatic and oncotic pressures"]'::jsonb, 0, 'Starling forces describe how high capillary hydrostatic pressure pushes fluid out while plasma oncotic pressure pulls fluid in; a rise in hydrostatic or fall in oncotic pressure favours interstitial fluid accumulation (oedema).', 'Anatomy & Physiology', '🧬', true),
(3739, 'Baroreceptor Reflex', 'AI Practice Question', 'Baroreceptors that help regulate blood pressure are primarily located in the:', '["Kidneys and liver","Carotid sinus and aortic arch","Lungs only","Adrenal medulla"]'::jsonb, 1, 'Baroreceptors in the carotid sinus and aortic arch detect changes in arterial wall stretch and relay signals to the medulla to adjust heart rate and vascular tone.', 'Anatomy & Physiology', '🧬', true),
(3740, 'Skin Anatomy', 'AI Practice Question', 'In classifying burn depth, a partial-thickness burn involves damage extending into the:', '["Epidermis only","Epidermis and part of the dermis","Subcutaneous fat only","Muscle and bone"]'::jsonb, 1, 'A partial-thickness (second-degree) burn damages the epidermis and part of the underlying dermis, often producing blistering and pain.', 'Anatomy & Physiology', '🧬', true),
(3741, 'Respiratory Anatomy', 'AI Practice Question', 'Gas exchange occurs in the respiratory zone, which includes the:', '["Trachea and bronchi","Respiratory bronchioles and alveoli","Larynx","Nasal cavity"]'::jsonb, 1, 'The respiratory zone — respiratory bronchioles, alveolar ducts, and alveoli — is where actual gas exchange with the pulmonary capillaries occurs, unlike the conducting zone which only transports air.', 'Anatomy & Physiology', '🧬', true),
(3742, 'Cranial Nerves', 'AI Practice Question', 'The gag reflex primarily depends on which cranial nerve(s)?', '["Cranial nerves I and II","Cranial nerves IX and X","Cranial nerve VII only","Cranial nerve XII only"]'::jsonb, 1, 'The glossopharyngeal (IX) and vagus (X) nerves mediate the sensory and motor components of the gag reflex, relevant to airway protection assessment.', 'Anatomy & Physiology', '🧬', true),
(3743, 'Cerebral Circulation', 'AI Practice Question', 'The Circle of Willis provides:', '["Venous drainage of the brain","An anastomotic arterial network providing collateral cerebral blood flow","Cerebrospinal fluid production","Lymphatic drainage of the brain"]'::jsonb, 1, 'The Circle of Willis is an arterial anastomosis at the base of the brain that provides collateral circulation, helping maintain perfusion if one contributing artery is occluded.', 'Anatomy & Physiology', '🧬', true),
(3744, 'Cardiac Output', 'AI Practice Question', 'Cardiac output is calculated as:', '["Heart rate divided by stroke volume","Heart rate multiplied by stroke volume","Stroke volume minus heart rate","Mean arterial pressure divided by heart rate"]'::jsonb, 1, 'Cardiac output (CO) = heart rate (HR) x stroke volume (SV), representing the volume of blood pumped by the heart per minute.', 'Anatomy & Physiology', '🧬', true),
(3745, 'Frank-Starling Law', 'AI Practice Question', 'The Frank-Starling law of the heart states that:', '["Increased venous return/preload increases stroke volume up to a physiological limit","Heart rate is unrelated to stroke volume","Afterload has no effect on cardiac output","Contractility is fixed regardless of stretch"]'::jsonb, 0, 'The Frank-Starling mechanism describes how increased ventricular filling (preload) stretches cardiac muscle fibres, increasing the force of contraction and stroke volume, up to a physiological limit.', 'Anatomy & Physiology', '🧬', true),
(3746, 'Hepatic Anatomy', 'AI Practice Question', 'The hepatic portal vein primarily carries blood from the:', '["Heart to the liver","Gastrointestinal tract and spleen to the liver","Liver to the systemic circulation only","Kidneys to the liver"]'::jsonb, 1, 'The hepatic portal vein drains nutrient- and sometimes toxin-rich blood from the GI tract and spleen into the liver for processing before it enters systemic circulation.', 'Anatomy & Physiology', '🧬', true),
(3747, 'Vascular Anatomy', 'AI Practice Question', 'During subclavian central line insertion, the vein lies:', '["Anterior to the subclavian artery, posterior to the clavicle","Lateral to the carotid artery only","Superior to the clavicle at all times","Within the mediastinum only"]'::jsonb, 0, 'The subclavian vein runs anterior to the subclavian artery and posterior to the middle third of the clavicle, a key anatomical relationship for safe central line placement.', 'Anatomy & Physiology', '🧬', true),
(3748, 'Blood Groups', 'AI Practice Question', 'A patient with blood group O negative is often called the:', '["Universal recipient","Universal donor","Least compatible donor","Rh-positive donor"]'::jsonb, 1, 'O negative red cells lack A, B, and Rh(D) antigens, making them compatible (in emergencies) with recipients of any ABO/Rh type — hence ''universal donor''.', 'Anatomy & Physiology', '🧬', true),
(3749, 'Muscle Physiology', 'AI Practice Question', 'A motor unit is defined as:', '["A single muscle fibre","One motor neuron and all the muscle fibres it innervates","A group of tendons","A type of neuromuscular junction disease"]'::jsonb, 1, 'A motor unit consists of a single motor neuron together with every muscle fibre it innervates, functioning as the basic unit of voluntary muscle contraction.', 'Anatomy & Physiology', '🧬', true),
(3750, 'Lymphatic System', 'AI Practice Question', 'A key function of the lymphatic system is to:', '["Produce red blood cells","Return interstitial fluid to the circulation and support immune defence","Regulate blood glucose","Filter urine"]'::jsonb, 1, 'The lymphatic system drains excess interstitial fluid back into venous circulation and plays a central role in immune surveillance and defence.', 'Anatomy & Physiology', '🧬', true),
(3751, 'GI Physiology', 'AI Practice Question', 'Most nutrient absorption occurs in the:', '["Stomach","Small intestine","Large intestine","Oesophagus"]'::jsonb, 1, 'The small intestine, with its vast surface area from villi and microvilli, is the primary site of digestion and nutrient absorption.', 'Anatomy & Physiology', '🧬', true),
(3752, 'Pancreatic Physiology', 'AI Practice Question', 'The pancreas functions as both an endocrine and exocrine organ; insulin is an example of its:', '["Exocrine function","Endocrine function","Neither function","Only a digestive enzyme"]'::jsonb, 1, 'Insulin, secreted by the islets of Langerhans directly into the bloodstream, exemplifies the pancreas''s endocrine function, distinct from its exocrine secretion of digestive enzymes into the duodenum.', 'Anatomy & Physiology', '🧬', true),
(3753, 'Brainstem Physiology', 'AI Practice Question', 'Vital cardiorespiratory centres are located in the:', '["Cerebellum","Medulla oblongata","Occipital lobe","Hypothalamus only"]'::jsonb, 1, 'The medulla oblongata houses the cardiac and respiratory centres that regulate heart rate, blood pressure, and breathing rhythm.', 'Anatomy & Physiology', '🧬', true),
(3754, 'Renal Physiology', 'AI Practice Question', 'Renal autoregulation helps maintain a relatively constant:', '["Urine colour","Glomerular filtration rate across a range of blood pressures","Bladder capacity","Serum potassium only"]'::jsonb, 1, 'Renal autoregulation (via myogenic and tubuloglomerular feedback mechanisms) keeps renal blood flow and glomerular filtration rate relatively stable despite fluctuations in systemic blood pressure.', 'Anatomy & Physiology', '🧬', true),
(3755, 'Electronic Health Records', 'AI Practice Question', 'A primary benefit of electronic health records (EHR) over paper records is:', '["Slower access to patient information","Improved accessibility, legibility, and coordination of care across providers","Elimination of all documentation errors","No need for staff training"]'::jsonb, 1, 'EHRs improve accessibility and legibility of patient data and support coordinated care across multiple providers and settings, though they do not eliminate all error types.', 'Nursing Informatics & ICT', '💻', true),
(3756, 'Barcode Medication Administration', 'AI Practice Question', 'The main purpose of barcode medication administration (BCMA) is to:', '["Speed up medication rounds regardless of accuracy","Verify the five rights of medication administration and reduce medication errors","Replace the need for a medication administration record","Track staff attendance"]'::jsonb, 1, 'BCMA scans patient and medication barcodes to confirm the right patient, drug, dose, route, and time, reducing administration errors.', 'Nursing Informatics & ICT', '💻', true),
(3757, 'Data Confidentiality', 'AI Practice Question', 'Sharing your personal EHR login credentials with a colleague is:', '["Acceptable if they are busy","A breach of data confidentiality and accountability","Required by hospital policy","Only a problem if a wrong entry is made"]'::jsonb, 1, 'Login credentials are personal and tied to individual accountability; sharing them breaches confidentiality policy and undermines the audit trail of who accessed or changed a record.', 'Nursing Informatics & ICT', '💻', true),
(3758, 'Telehealth', 'AI Practice Question', 'Tele-ICU (remote ICU monitoring) primarily allows:', '["Elimination of bedside nurses","Remote specialists to monitor and support ICU care across multiple sites","Only administrative record-keeping","Replacement of ventilator alarms"]'::jsonb, 1, 'Tele-ICU connects remote intensivists/specialists to bedside teams via cameras and data feeds, extending expert oversight to ICUs that may lack on-site specialists around the clock.', 'Nursing Informatics & ICT', '💻', true),
(3759, 'Clinical Decision Support', 'AI Practice Question', 'A clinical decision support system (CDSS) in an EHR is designed to:', '["Automatically treat the patient without clinician input","Alert clinicians to potential issues such as drug interactions or abnormal values","Replace nursing assessment","Only manage billing"]'::jsonb, 1, 'CDSS tools generate alerts (e.g. drug-drug interactions, allergy warnings, abnormal lab flags) to support — not replace — clinical judgement.', 'Nursing Informatics & ICT', '💻', true),
(3760, 'Interoperability', 'AI Practice Question', 'Health Level Seven (HL7) standards exist primarily to support:', '["Hospital parking systems","Interoperability and standardised exchange of health information between systems","Only nursing schedules","Physical security of hospital buildings"]'::jsonb, 1, 'HL7 standards define how clinical and administrative data are structured and exchanged so that different health information systems can communicate with each other.', 'Nursing Informatics & ICT', '💻', true),
(3761, 'System Downtime', 'AI Practice Question', 'During an EHR system downtime, the priority nursing action is to:', '["Stop documenting entirely until systems return","Switch to established downtime/manual documentation procedures","Discharge all patients","Wait without informing anyone"]'::jsonb, 1, 'Facilities maintain downtime procedures (paper backup forms) so that essential documentation and safe care continue uninterrupted until systems are restored.', 'Nursing Informatics & ICT', '💻', true),
(3762, 'Cybersecurity', 'AI Practice Question', 'A phishing email pretending to be from IT asking staff to ''confirm'' their password is an example of:', '["A legitimate security update","A social engineering cybersecurity threat","A required annual login refresh","A harmless marketing email"]'::jsonb, 1, 'Phishing is a social engineering technique that tricks users into revealing credentials or sensitive data, a major cybersecurity threat in healthcare settings.', 'Nursing Informatics & ICT', '💻', true),
(3763, 'Nursing Informatics', 'AI Practice Question', 'Nursing informatics is best defined as the specialty that:', '["Focuses only on hospital billing software","Integrates nursing science with information and computer science to manage and communicate data, information, and knowledge","Replaces the need for clinical nursing skills","Is only relevant to IT department staff"]'::jsonb, 1, 'Nursing informatics integrates nursing science, computer science, and information science to support clinical decision-making and improve patient care through data and technology.', 'Nursing Informatics & ICT', '💻', true),
(3764, 'Data Breach', 'AI Practice Question', 'If a nurse suspects a patient data breach has occurred, the appropriate first action is to:', '["Ignore it if no harm seems obvious","Report it immediately according to institutional policy","Delete the affected records","Discuss it publicly with colleagues on social media"]'::jsonb, 1, 'Suspected breaches must be reported promptly through official channels so they can be investigated, contained, and, where required, disclosed per policy/regulation.', 'Nursing Informatics & ICT', '💻', true),
(3765, 'Alarm Fatigue', 'AI Practice Question', 'Alarm fatigue in a technology-dense ICU environment refers to:', '["Improved responsiveness to all alarms","Desensitisation to alarms from excessive frequency, leading to delayed or missed responses","A malfunction unique to ventilators","A benefit of increased monitoring"]'::jsonb, 1, 'Alarm fatigue occurs when frequent, often non-actionable alarms desensitise staff, increasing the risk that a true critical alarm is missed or responded to late.', 'Nursing Informatics & ICT', '💻', true),
(3766, 'Standardised Terminology', 'AI Practice Question', 'Standardised nursing terminologies such as NANDA, NIC, and NOC exist to:', '["Make documentation more variable between institutions","Provide a consistent language for nursing diagnoses, interventions, and outcomes","Replace physician orders","Track hospital finances"]'::jsonb, 1, 'Standardised terminologies give nurses a shared, consistent vocabulary for diagnoses, interventions, and outcomes, supporting communication, research, and data aggregation.', 'Nursing Informatics & ICT', '💻', true),
(3767, 'eMAR', 'AI Practice Question', 'An advantage of the electronic medication administration record (eMAR) over paper MARs is:', '["It cannot be updated in real time","Real-time updates and reduced transcription error risk","It requires no cross-check with the pharmacy system","It eliminates the need for the five rights of administration"]'::jsonb, 1, 'eMAR systems update in real time and are typically integrated with pharmacy and BCMA systems, reducing transcription errors compared to handwritten paper MARs.', 'Nursing Informatics & ICT', '💻', true),
(3768, 'Evidence-Based Practice Databases', 'AI Practice Question', 'CINAHL and PubMed are examples of:', '["Hospital scheduling systems","Databases used to search nursing and biomedical literature for evidence-based practice","Electronic medication systems","Patient billing platforms"]'::jsonb, 1, 'CINAHL and PubMed are literature databases nurses use to locate research evidence to inform evidence-based practice.', 'Nursing Informatics & ICT', '💻', true),
(3769, 'Remote Monitoring', 'AI Practice Question', 'Wearable remote patient monitoring devices in critical care follow-up are used to:', '["Replace all in-person assessment permanently","Continuously track physiological parameters and alert clinicians to deterioration outside the hospital","Only record step counts","Provide entertainment for patients"]'::jsonb, 1, 'Remote monitoring devices track parameters like heart rate, SpO2, or rhythm after discharge, helping detect early deterioration and reduce readmissions.', 'Nursing Informatics & ICT', '💻', true),
(3770, 'Audit Trail', 'AI Practice Question', 'An EHR audit trail is used to:', '["Track who accessed or modified a patient record and when","Automatically diagnose patients","Replace nursing notes","Calculate medication dosages"]'::jsonb, 0, 'Audit trails log every access and modification to a patient''s electronic record, supporting accountability, security investigations, and legal/regulatory compliance.', 'Nursing Informatics & ICT', '💻', true),
(3771, 'Authentication Security', 'AI Practice Question', 'Two-factor authentication improves EHR security by:', '["Requiring only a username","Requiring a second independent verification step beyond just a password","Allowing shared generic logins","Disabling password requirements"]'::jsonb, 1, 'Two-factor authentication adds a second verification layer (e.g. a code sent to a device) beyond the password, making unauthorised access significantly harder.', 'Nursing Informatics & ICT', '💻', true),
(3772, 'Data Encryption', 'AI Practice Question', 'Encrypting patient data primarily protects against:', '["Slower data transmission","Unauthorised parties reading intercepted or stolen data","Loss of internet connectivity","Hardware failure"]'::jsonb, 1, 'Encryption converts data into unreadable code without the correct key, protecting patient information if it is intercepted, lost, or stolen.', 'Nursing Informatics & ICT', '💻', true),
(3773, 'Documentation Integrity', 'AI Practice Question', 'Copy-pasting a previous nursing note into today''s entry without verifying current accuracy risks:', '["Improved efficiency with no downside","Documentation errors and propagation of outdated or inaccurate information (''note bloat'')","Better legal protection","Faster patient discharge"]'::jsonb, 1, 'Copy-forward/copy-paste documentation can propagate outdated, inaccurate, or irrelevant information, a recognised patient safety and legal risk in EHR use.', 'Nursing Informatics & ICT', '💻', true),
(3774, 'Downtime Backup', 'AI Practice Question', 'A key component of EHR downtime preparedness is:', '["Assuming downtime will never happen","Maintaining accessible, up-to-date paper/manual backup procedures and staff training on them","Relying solely on personal memory","Disabling all monitors during downtime"]'::jsonb, 1, 'Effective downtime preparedness includes readily available manual backup forms and staff who are trained and drilled on using them so care isn''t disrupted.', 'Nursing Informatics & ICT', '💻', true),
(3775, 'Chest X-Ray - ETT Position', 'AI Practice Question', 'On a chest X-ray, correct endotracheal tube tip position is approximately:', '["At the level of the carina","2–4cm above the carina","In the right mainstem bronchus","At the level of the vocal cords"]'::jsonb, 1, 'The ETT tip should sit roughly 2–4cm above the carina (around the T2–T4 vertebral level) to avoid mainstem intubation or accidental extubation with head movement.', 'Radiology & Imaging', '🩻', true),
(3776, 'Chest X-Ray - Pneumothorax', 'AI Practice Question', 'A key chest X-ray sign of pneumothorax is:', '["Increased lung markings throughout","Absence of lung markings peripheral to a visible pleural line","Bilateral diffuse infiltrates","Widened mediastinum"]'::jsonb, 1, 'Pneumothorax appears as a region with absent peripheral lung markings beyond a visible visceral pleural edge, sometimes with tracheal/mediastinal shift in tension pneumothorax.', 'Radiology & Imaging', '🩻', true),
(3777, 'NG Tube Confirmation', 'AI Practice Question', 'Radiographic confirmation of correct nasogastric tube placement shows the tip:', '["Coiled in the oesophagus","Below the diaphragm, in the stomach","In the right lung field","At the level of the carina"]'::jsonb, 1, 'A correctly placed NG tube''s tip is seen on X-ray crossing the diaphragm and lying within the stomach, well below the diaphragm and away from the bronchial tree.', 'Radiology & Imaging', '🩻', true),
(3778, 'CT Head - Raised ICP', 'AI Practice Question', 'CT head findings suggestive of raised intracranial pressure include:', '["Symmetric ventricles with clear sulci","Midline shift and effacement (compression) of the ventricles","Normal grey-white matter differentiation only","Absence of any mass effect"]'::jsonb, 1, 'Midline shift, effaced (compressed) ventricles, and loss of sulcal spaces on CT suggest raised intracranial pressure and mass effect.', 'Radiology & Imaging', '🩻', true),
(3779, 'Contrast Media Reaction', 'AI Practice Question', 'A patient receiving IV contrast who develops hives, itching, and wheeze is most likely experiencing:', '["Normal expected sensation","A contrast media hypersensitivity reaction","Signs of adequate hydration","A vagal response only"]'::jsonb, 1, 'Hives, pruritus, and wheeze after IV contrast administration indicate an allergic-type hypersensitivity reaction, requiring prompt recognition and treatment (antihistamines, steroids, or epinephrine depending on severity).', 'Radiology & Imaging', '🩻', true),
(3780, 'FAST Scan', 'AI Practice Question', 'The FAST scan (Focused Assessment with Sonography in Trauma) is primarily used to detect:', '["Fractures of long bones","Free fluid (suggesting haemorrhage) in the abdomen, pelvis, and pericardium","Pneumonia","Cervical spine injury"]'::jsonb, 1, 'FAST is a rapid bedside ultrasound examination used to detect free intraperitoneal or pericardial fluid, typically blood, in trauma patients.', 'Radiology & Imaging', '🩻', true),
(3781, 'MRI Safety', 'AI Practice Question', 'An absolute contraindication to MRI scanning is:', '["Mild claustrophobia","A non-MRI-conditional cardiac pacemaker or ferromagnetic implant","Recent blood test","Pregnancy in the second trimester (with appropriate precautions)"]'::jsonb, 1, 'Ferromagnetic implants or non-MRI-conditional devices such as certain pacemakers can be displaced or malfunction in the MRI''s strong magnetic field, making them absolute contraindications.', 'Radiology & Imaging', '🩻', true),
(3782, 'Radiation Safety', 'AI Practice Question', 'The ALARA principle in radiologic imaging stands for:', '["Always Limit Additional Radiographic Access","As Low As Reasonably Achievable (radiation exposure)","A Legal Requirement for All Radiographs","Any Level Achievable with Repeated Attempts"]'::jsonb, 1, 'ALARA (''As Low As Reasonably Achievable'') guides minimising radiation exposure to patients and staff while still obtaining diagnostically useful images.', 'Radiology & Imaging', '🩻', true),
(3783, 'CT Pulmonary Angiogram', 'AI Practice Question', 'CT pulmonary angiography is the imaging investigation of choice to diagnose:', '["Pulmonary embolism","Simple rib fracture","Peptic ulcer disease","Osteoarthritis"]'::jsonb, 0, 'CT pulmonary angiography directly visualises contrast-filled pulmonary arteries and is the standard imaging test to confirm or exclude pulmonary embolism.', 'Radiology & Imaging', '🩻', true),
(3784, 'Silhouette Sign', 'AI Practice Question', 'On chest X-ray, the ''silhouette sign'' helps to:', '["Diagnose fractures","Localise the anatomical location of consolidation or a mass by which normal border it obscures","Measure heart rate","Assess bone density"]'::jsonb, 1, 'The silhouette sign describes loss of a normally visible anatomical border (e.g. heart border, diaphragm) when adjacent lung tissue is consolidated, helping localise the pathology.', 'Radiology & Imaging', '🩻', true),
(3785, 'Ultrasound-Guided Central Line', 'AI Practice Question', 'Using ultrasound guidance for central line insertion primarily helps to:', '["Eliminate the need for sterile technique","Visualise the vein in real time and reduce mechanical complications","Replace the need for a post-procedure chest X-ray in all cases","Increase radiation exposure"]'::jsonb, 1, 'Real-time ultrasound guidance allows direct visualisation of the target vein and needle tip, reducing complications such as arterial puncture, pneumothorax, and failed cannulation attempts.', 'Radiology & Imaging', '🩻', true),
(3786, 'Pleural Effusion', 'AI Practice Question', 'A classic chest X-ray sign of pleural effusion is:', '["Hyperinflated lung fields","Blunting of the costophrenic angle","A widened mediastinum","Free air under the diaphragm"]'::jsonb, 1, 'Fluid accumulating in the pleural space characteristically blunts (obscures) the normally sharp costophrenic angle on an upright chest X-ray.', 'Radiology & Imaging', '🩻', true),
(3787, 'Widened Mediastinum', 'AI Practice Question', 'A widened mediastinum on chest X-ray after trauma raises suspicion for:', '["Simple pneumonia","Traumatic aortic injury/dissection","Normal anatomical variant in all patients","Peptic ulcer perforation"]'::jsonb, 1, 'A widened mediastinum following blunt chest trauma is a red-flag sign that warrants urgent evaluation for traumatic aortic injury.', 'Radiology & Imaging', '🩻', true),
(3788, 'Radiation Shielding', 'AI Practice Question', 'Lead aprons used during fluoroscopy or portable X-rays function to:', '["Improve image contrast","Shield staff and non-target areas of the patient from scatter radiation","Increase radiation dose intentionally","Replace the need for distance as a protective measure"]'::jsonb, 1, 'Lead aprons attenuate scatter radiation, protecting staff and non-targeted body areas, complementing the other radiation safety principles of time, distance, and shielding.', 'Radiology & Imaging', '🩻', true),
(3789, 'Imaging in Pregnancy', 'AI Practice Question', 'When abdominal/pelvic imaging is required in a pregnant patient, the priority is to:', '["Always avoid any imaging regardless of maternal risk","Use the lowest radiation dose necessary and consider non-ionising alternatives (e.g. ultrasound) when feasible","Use the highest dose to ensure clear images","Ignore gestational age"]'::jsonb, 1, 'When imaging is clinically necessary in pregnancy, clinicians minimise radiation dose, use shielding, and favour non-ionising modalities like ultrasound where diagnostically adequate.', 'Radiology & Imaging', '🩻', true),
(3790, 'Endobronchial Intubation', 'AI Practice Question', 'A chest X-ray showing a radiopaque ETT tip well below the carina with unilateral lung opacification suggests:', '["Correct tube placement","Right mainstem (endobronchial) intubation","Oesophageal intubation","Tension pneumothorax"]'::jsonb, 1, 'A tube advanced too far typically enters the more vertically-angled right mainstem bronchus, causing left lung under-ventilation/collapse and unilateral opacification.', 'Radiology & Imaging', '🩻', true),
(3791, 'Free Air Sign', 'AI Practice Question', 'Free air visible under the diaphragm on an erect abdominal/chest X-ray suggests:', '["Normal bowel gas pattern","Perforation of a hollow viscus","Ascites","Constipation"]'::jsonb, 1, 'Free intraperitoneal air under the diaphragm on an erect film is a classic sign of perforation of a hollow abdominal organ, requiring urgent surgical evaluation.', 'Radiology & Imaging', '🩻', true),
(3792, 'Doppler Ultrasound', 'AI Practice Question', 'Doppler ultrasound is particularly useful for assessing:', '["Bone density","Blood flow and vascular patency (e.g. DVT, graft/fistula flow)","Lung consolidation","Brain electrical activity"]'::jsonb, 1, 'Doppler ultrasound measures blood flow characteristics, making it valuable for diagnosing DVT, assessing vascular graft/fistula patency, and evaluating perfusion.', 'Radiology & Imaging', '🩻', true),
(3793, 'Acute Stroke Imaging', 'AI Practice Question', 'The first-line imaging investigation in suspected acute stroke is:', '["MRI with contrast","Non-contrast CT head","Abdominal ultrasound","Chest X-ray"]'::jsonb, 1, 'Non-contrast CT head is performed urgently in suspected stroke primarily to exclude haemorrhage before considering thrombolytic therapy.', 'Radiology & Imaging', '🩻', true),
(3794, 'Chest Tube Confirmation', 'AI Practice Question', 'After chest tube insertion, a chest X-ray is obtained primarily to confirm:', '["The patient''s blood type","Correct tube position and re-expansion of the lung","Cardiac rhythm","Renal function"]'::jsonb, 1, 'Post-insertion chest X-ray verifies that the chest tube is correctly positioned within the pleural space and that the lung is re-expanding as expected.', 'Radiology & Imaging', '🩻', true),
(3795, 'Full Blood Count', 'AI Practice Question', 'The normal haemoglobin range for an adult male is approximately:', '["6–8 g/dL","13.5–17.5 g/dL","20–24 g/dL","2–4 g/dL"]'::jsonb, 1, 'Normal adult male haemoglobin is roughly 13.5–17.5 g/dL, somewhat higher than the typical adult female range of about 12–15.5 g/dL.', 'Laboratory Sciences & Haematology', '🔬', true),
(3796, 'Coagulation Studies', 'AI Practice Question', 'For a patient on warfarin therapy, the therapeutic INR target for most indications is typically:', '["0.5–1.0","2.0–3.0","5.0–6.0","8.0–10.0"]'::jsonb, 1, 'Most indications for warfarin (e.g. atrial fibrillation, DVT/PE treatment) target an INR of 2.0–3.0; mechanical heart valves may require a higher target range.', 'Laboratory Sciences & Haematology', '🔬', true),
(3797, 'Coagulation Studies', 'AI Practice Question', 'Activated partial thromboplastin time (aPTT) is primarily used to monitor therapy with:', '["Warfarin","Unfractionated heparin","Aspirin","Ondansetron"]'::jsonb, 1, 'aPTT reflects the intrinsic coagulation pathway and is the standard test used to monitor and titrate unfractionated heparin infusions.', 'Laboratory Sciences & Haematology', '🔬', true),
(3798, 'Cardiac Biomarkers', 'AI Practice Question', 'Troponin is considered a highly specific biomarker for:', '["Renal injury","Myocardial injury","Hepatic injury","Pancreatic injury"]'::jsonb, 1, 'Cardiac troponin (I or T) is released specifically from injured cardiac myocytes, making it a highly sensitive and specific biomarker for myocardial injury.', 'Laboratory Sciences & Haematology', '🔬', true),
(3799, 'Cardiac Biomarkers', 'AI Practice Question', 'CK-MB (creatine kinase-MB) is used clinically to help assess:', '["Recent or ongoing myocardial injury, particularly reinfarction","Kidney function","Coagulation status","Blood glucose control"]'::jsonb, 0, 'CK-MB, while less specific than troponin, is still used in some settings to help detect reinfarction because it rises and falls faster than troponin.', 'Laboratory Sciences & Haematology', '🔬', true),
(3800, 'Inflammatory Markers', 'AI Practice Question', 'ESR and CRP are best described as:', '["Highly specific for a single disease","Nonspecific markers of inflammation","Direct measures of infection type","Measures of clotting function"]'::jsonb, 1, 'Erythrocyte sedimentation rate and C-reactive protein rise with inflammation from many causes and are nonspecific — useful for trend monitoring rather than diagnosing a specific condition.', 'Laboratory Sciences & Haematology', '🔬', true),
(3801, 'Blood Culture Technique', 'AI Practice Question', 'To reduce contamination risk, blood cultures should ideally be drawn:', '["From a single site only, after antibiotics are given","From two separate sites, ideally before starting antibiotics","Only from a central line hub","Without skin antisepsis"]'::jsonb, 1, 'Drawing cultures from two separate peripheral sites with proper skin antisepsis, ideally before antibiotic administration, improves diagnostic yield and reduces contamination and false negatives.', 'Laboratory Sciences & Haematology', '🔬', true),
(3802, 'DIC Lab Findings', 'AI Practice Question', 'Laboratory findings consistent with disseminated intravascular coagulation (DIC) include:', '["Shortened PT/aPTT and elevated platelets","Prolonged PT/aPTT, thrombocytopenia, low fibrinogen, and elevated D-dimer","Normal fibrinogen and normal D-dimer","Isolated elevated hemoglobin"]'::jsonb, 1, 'DIC consumes clotting factors and platelets, producing prolonged PT/aPTT, low platelets, low fibrinogen, and elevated D-dimer/fibrin degradation products.', 'Laboratory Sciences & Haematology', '🔬', true),
(3803, 'Transfusion Compatibility', 'AI Practice Question', 'The key difference between ''type and screen'' and ''type and crossmatch'' is that crossmatch:', '["Is faster and requires no blood sample","Actually tests the patient''s serum against the specific donor unit for compatibility","Only determines Rh status","Is only used for platelets"]'::jsonb, 1, 'Crossmatching physically mixes the patient''s serum with the specific donor unit to confirm compatibility, beyond just determining ABO/Rh type and screening for antibodies.', 'Laboratory Sciences & Haematology', '🔬', true),
(3804, 'Transfusion Reactions', 'AI Practice Question', 'Early signs of an acute haemolytic transfusion reaction include:', '["Improved vital signs","Fever, chills, flank pain, and hypotension shortly after starting the transfusion","Delayed symptoms after 2 weeks only","No change in vital signs"]'::jsonb, 1, 'Acute haemolytic reactions typically present rapidly with fever, chills, flank/back pain, hypotension, and haemoglobinuria, requiring immediate transfusion cessation.', 'Laboratory Sciences & Haematology', '🔬', true),
(3805, 'Anaemia Classification', 'AI Practice Question', 'Microcytic anaemia (low MCV) is classically associated with:', '["Iron deficiency","Vitamin B12 deficiency","Folate deficiency","Acute haemorrhage only"]'::jsonb, 0, 'Iron deficiency anaemia is the classic cause of microcytic (small red cell) anaemia, whereas B12/folate deficiency typically causes macrocytic anaemia.', 'Laboratory Sciences & Haematology', '🔬', true),
(3806, 'Platelet Function', 'AI Practice Question', 'Spontaneous bleeding risk significantly increases when the platelet count falls below approximately:', '["150,000/microL","100,000/microL","10,000–20,000/microL","250,000/microL"]'::jsonb, 2, 'Spontaneous bleeding risk rises sharply when platelets drop to roughly 10,000–20,000/microL, though risk begins increasing well before this level, especially with additional bleeding risk factors.', 'Laboratory Sciences & Haematology', '🔬', true),
(3807, 'Liver Function Tests', 'AI Practice Question', 'Elevated ALT and AST primarily indicate:', '["Renal dysfunction","Hepatocellular injury","Pancreatic dysfunction only","Coagulopathy directly"]'::jsonb, 1, 'ALT and AST are intracellular liver enzymes released into the blood when hepatocytes are injured, making them markers of hepatocellular damage.', 'Laboratory Sciences & Haematology', '🔬', true),
(3808, 'Renal Function Tests', 'AI Practice Question', 'An elevated BUN:creatinine ratio (greater than 20:1) suggests:', '["Intrinsic renal disease","Prerenal azotaemia (e.g. dehydration, hypoperfusion)","Postrenal obstruction only","Normal renal function"]'::jsonb, 1, 'A disproportionately elevated BUN relative to creatinine suggests prerenal causes such as dehydration or reduced renal perfusion, where urea reabsorption increases more than creatinine.', 'Laboratory Sciences & Haematology', '🔬', true),
(3809, 'Sputum Culture', 'AI Practice Question', 'Sputum culture and sensitivity testing is primarily indicated to:', '["Diagnose myocardial infarction","Identify the causative organism and guide antibiotic therapy in suspected respiratory infection","Assess renal function","Measure blood glucose"]'::jsonb, 1, 'Sputum culture helps identify the pathogen responsible for a respiratory infection and its antibiotic sensitivities, guiding targeted therapy.', 'Laboratory Sciences & Haematology', '🔬', true),
(3810, 'ABG Sample Handling', 'AI Practice Question', 'Improper handling of an arterial blood gas sample, such as air bubble contamination, can falsely:', '["Have no effect on results","Alter measured PaO2 and PaCO2 values","Only affect potassium level","Improve accuracy"]'::jsonb, 1, 'Air bubbles in an ABG syringe can equilibrate with the sample, falsely raising PaO2 and altering PaCO2, so bubbles should be expelled promptly and the sample analysed quickly.', 'Laboratory Sciences & Haematology', '🔬', true),
(3811, 'HbA1c', 'AI Practice Question', 'Glycosylated haemoglobin (HbA1c) reflects average blood glucose control over approximately:', '["The past 24 hours","The past 2–3 months","The past 5 years","A single fasting measurement"]'::jsonb, 1, 'HbA1c reflects the percentage of haemoglobin glycosylated over the roughly 120-day lifespan of red blood cells, giving an average picture of glycaemic control over about 2–3 months.', 'Laboratory Sciences & Haematology', '🔬', true),
(3812, 'Coombs Test', 'AI Practice Question', 'The direct Coombs test is used to detect:', '["Antibodies bound to the surface of red blood cells","Platelet aggregation","White cell count","Clotting factor deficiency"]'::jsonb, 0, 'The direct Coombs (antiglobulin) test detects antibodies or complement already bound to the patient''s red blood cells, useful in diagnosing haemolytic conditions and transfusion reactions.', 'Laboratory Sciences & Haematology', '🔬', true),
(3813, 'Coagulation Physiology', 'AI Practice Question', 'Fibrinogen plays its key role in coagulation by:', '["Inhibiting platelet aggregation","Being converted to fibrin to form the structural clot mesh","Breaking down existing clots","Regulating serum calcium"]'::jsonb, 1, 'Thrombin converts soluble fibrinogen into insoluble fibrin strands, which cross-link to form the structural mesh of a stable clot.', 'Laboratory Sciences & Haematology', '🔬', true),
(3814, 'Lactate in Shock', 'AI Practice Question', 'A rising serum lactate level in a critically ill patient most often indicates:', '["Improved tissue perfusion","Tissue hypoperfusion and anaerobic metabolism","Normal metabolic state","Overhydration only"]'::jsonb, 1, 'Elevated lactate reflects anaerobic metabolism from inadequate tissue oxygen delivery, making it a key marker of shock severity and a target for resuscitation trending.', 'Laboratory Sciences & Haematology', '🔬', true),
(3815, 'Triage Systems', 'AI Practice Question', 'In the START triage system, a patient who is not breathing even after airway repositioning is categorised as:', '["Immediate (red)","Delayed (yellow)","Minor (green)","Deceased/expectant (black)"]'::jsonb, 3, 'In START triage, a patient without spontaneous respirations even after repositioning the airway is classified as deceased/expectant (black), reflecting the reality of limited resources in mass casualty settings.', 'Disaster & Emergency Nursing', '🚨', true),
(3816, 'Disaster Phases', 'AI Practice Question', 'The four recognised phases of disaster management are:', '["Mitigation, preparedness, response, and recovery","Triage, treatment, transport, and discharge","Alert, alarm, action, and audit","Planning, funding, staffing, and closure"]'::jsonb, 0, 'The disaster management cycle is commonly described in four phases: mitigation (reducing risk), preparedness, response, and recovery.', 'Disaster & Emergency Nursing', '🚨', true),
(3817, 'Decontamination', 'AI Practice Question', 'Before treating a patient exposed to a hazardous chemical agent, the priority is to:', '["Begin advanced life support immediately without decontamination","Perform decontamination to prevent secondary contamination of staff and facilities","Transport the patient directly to the ICU","Skip PPE if the patient appears stable"]'::jsonb, 1, 'Decontamination must generally occur before a chemically contaminated patient enters clinical areas, protecting responders and the facility from secondary contamination.', 'Disaster & Emergency Nursing', '🚨', true),
(3818, 'Incident Command', 'AI Practice Question', 'The Hospital Incident Command System (HICS) exists to:', '["Replace the need for any planning","Provide a standardised organisational structure for coordinating hospital disaster response","Only manage financial billing during a disaster","Apply exclusively to fire emergencies"]'::jsonb, 1, 'HICS provides a standardised command structure with clear roles and reporting lines, improving coordination and communication during a hospital''s disaster response.', 'Disaster & Emergency Nursing', '🚨', true),
(3819, 'PPE Levels', 'AI Practice Question', 'Level A personal protective equipment, the highest level of protection, is used when:', '["No respiratory or skin hazard exists","The highest level of respiratory and skin protection is required, such as unknown highly hazardous substances","Only gloves are needed","Working in a standard clinical ward"]'::jsonb, 1, 'Level A PPE (fully encapsulating suit with self-contained breathing apparatus) provides the highest protection, reserved for situations with unknown or highly hazardous airborne/contact substances.', 'Disaster & Emergency Nursing', '🚨', true),
(3820, 'Triage Tags', 'AI Practice Question', 'In standard mass casualty triage tagging, the colour red indicates:', '["Minor injuries, can wait","Immediate, life-threatening injuries requiring urgent care","Deceased or expectant","Delayed care acceptable"]'::jsonb, 1, 'Red tags indicate patients with immediate, life-threatening conditions who require urgent intervention to survive.', 'Disaster & Emergency Nursing', '🚨', true),
(3821, 'Mass Casualty Incident', 'AI Practice Question', 'A mass casualty incident (MCI) is defined as an event where:', '["Patient needs exceed available resources, requiring altered standards of care","Only one patient is critically injured","Resources always exceed patient needs","It occurs exclusively in rural areas"]'::jsonb, 0, 'An MCI is characterised by the number of casualties overwhelming available resources, requiring triage and altered (crisis) standards of care to do the greatest good for the greatest number.', 'Disaster & Emergency Nursing', '🚨', true),
(3822, 'Evacuation Procedures', 'AI Practice Question', 'Horizontal evacuation during an internal hospital emergency (e.g. fire) involves:', '["Moving patients to a different floor via stairwells","Moving patients through a fire/smoke barrier to an adjoining, safer area on the same floor","Evacuating the entire building immediately in all cases","Only evacuating ambulatory patients"]'::jsonb, 1, 'Horizontal evacuation moves patients through fire-rated doors/barriers to a safer area on the same floor, often preferred initially over full building evacuation.', 'Disaster & Emergency Nursing', '🚨', true),
(3823, 'Radiation Exposure Principles', 'AI Practice Question', 'The three core principles for minimising radiation exposure during a radiological incident are:', '["Time, distance, and shielding","Speed, volume, and pressure","Triage, treatment, and transport","Isolation, ventilation, and hydration"]'::jsonb, 0, 'Limiting exposure time, maximising distance from the source, and using shielding are the three fundamental principles for reducing radiation dose during a radiological event.', 'Disaster & Emergency Nursing', '🚨', true),
(3824, 'Biological Agents', 'AI Practice Question', 'Anthrax is classified as a potential agent of concern in disaster/bioterrorism preparedness because it:', '["Is only mildly contagious with no severe effects","Can cause severe illness and has known potential for use as a biological weapon","Only affects animals, never humans","Requires no isolation precautions"]'::jsonb, 1, 'Anthrax (Bacillus anthracis) is recognised as a category A bioterrorism agent due to its potential for severe illness, environmental persistence as spores, and historical use as a weapon.', 'Disaster & Emergency Nursing', '🚨', true),
(3825, 'Emergency Preparedness Plans', 'AI Practice Question', 'A critical component of any institutional emergency preparedness plan is:', '["A clear communication plan for internal and external coordination","Avoiding any staff training or drills","Excluding community partners from planning","Assuming resources will always be adequate"]'::jsonb, 0, 'A robust communication plan — connecting staff, leadership, and external agencies — is essential for coordinated, effective emergency response.', 'Disaster & Emergency Nursing', '🚨', true),
(3826, 'Surge Capacity', 'AI Practice Question', 'Hospital ''surge capacity'' refers to the ability to:', '["Reduce patient volume during normal operations","Rapidly expand capacity to manage a substantial increase in patient volume during a disaster","Close down non-essential services permanently","Refuse additional patients during a crisis"]'::jsonb, 1, 'Surge capacity describes a facility''s ability to expand staffing, space, and supplies rapidly to accommodate a sudden, significant increase in patient volume.', 'Disaster & Emergency Nursing', '🚨', true),
(3827, 'Triage Reassessment', 'AI Practice Question', 'Triage during a mass casualty event should be considered:', '["A one-time assessment only","An ongoing, dynamic process requiring reassessment as patient condition or resources change","Unnecessary once initial tags are applied","Only the responsibility of physicians"]'::jsonb, 1, 'Patient condition and available resources can change rapidly, so triage categories must be reassessed continuously throughout the response.', 'Disaster & Emergency Nursing', '🚨', true),
(3828, 'Search and Rescue', 'AI Practice Question', 'During urban search and rescue operations, the initial priority for responders is typically:', '["Immediate extrication of all victims regardless of scene safety","Scene safety assessment before entering a hazardous structure","Providing definitive surgical care on-site","Documentation of property damage"]'::jsonb, 1, 'Ensuring scene safety is the first priority in search and rescue — responders must avoid becoming additional casualties before attempting extrication or treatment.', 'Disaster & Emergency Nursing', '🚨', true),
(3829, 'Psychological First Aid', 'AI Practice Question', 'Psychological first aid provided after a disaster primarily aims to:', '["Provide formal long-term psychotherapy on-site","Promote safety, calm, connectedness, self-efficacy, and hope in the acute aftermath","Diagnose psychiatric disorders immediately","Replace the need for any follow-up mental health care"]'::jsonb, 1, 'Psychological first aid is a supportive, non-clinical approach focused on immediate comfort, safety, and connecting survivors to ongoing resources, not formal therapy.', 'Disaster & Emergency Nursing', '🚨', true),
(3830, 'Burn Triage in MCI', 'AI Practice Question', 'In a mass casualty incident involving burns, triage prioritisation typically considers:', '["Burn size alone, ignoring airway status","Total body surface area burned together with airway involvement and other injuries","Only the patient''s age","Cosmetic appearance of the burn"]'::jsonb, 1, 'Burn triage in an MCI weighs airway involvement, total body surface area burned, and associated injuries together, since airway compromise can be immediately life-threatening regardless of burn size.', 'Disaster & Emergency Nursing', '🚨', true),
(3831, 'Incident Command Post', 'AI Practice Question', 'The role of the incident command post during a disaster response is to:', '["Provide direct bedside patient care","Serve as the centralised coordination point for managing the overall response","Replace the emergency department entirely","Handle only media relations"]'::jsonb, 1, 'The incident command post is the centralised hub where response coordination, resource allocation, and communication decisions are managed during an emergency.', 'Disaster & Emergency Nursing', '🚨', true),
(3832, 'Just-in-Time Training', 'AI Practice Question', '''Just-in-time'' training during a disaster response refers to:', '["Formal training completed years in advance only","Brief, focused training delivered immediately before staff perform an unfamiliar task during the event","Training that is never actually needed","Training reserved only for physicians"]'::jsonb, 1, 'Just-in-time training provides rapid, focused instruction immediately before an unfamiliar task (e.g. donning unfamiliar PPE) is performed during an active response, when formal training wasn''t previously completed.', 'Disaster & Emergency Nursing', '🚨', true),
(3833, 'Early Mobilization', 'AI Practice Question', 'Early mobilisation of critically ill patients in the ICU is associated with:', '["Increased ICU-acquired weakness","Reduced ICU-acquired weakness, delirium, and length of stay","No measurable clinical benefit","Increased ventilator days in all cases"]'::jsonb, 1, 'Evidence supports that early, progressive mobilisation reduces ICU-acquired weakness, delirium duration, and overall length of stay when performed safely.', 'Rehabilitation & Mobilization', '🏃', true),
(3834, 'ICU-Acquired Weakness', 'AI Practice Question', 'A major risk factor for ICU-acquired weakness includes:', '["Early ambulation","Prolonged immobility, sepsis, and prolonged neuromuscular blockade","Adequate nutrition","Short ICU stay"]'::jsonb, 1, 'Prolonged bed rest, sepsis/systemic inflammation, hyperglycaemia, and prolonged neuromuscular blocking agent use are recognised risk factors for ICU-acquired weakness.', 'Rehabilitation & Mobilization', '🏃', true),
(3835, 'Passive ROM Exercises', 'AI Practice Question', 'Passive range-of-motion exercises are particularly indicated for patients who:', '["Are fully mobile and independent","Cannot actively move a limb, such as unconscious or paralysed patients","Have no risk of contractures","Are being discharged same-day"]'::jsonb, 1, 'Passive ROM exercises maintain joint mobility and reduce contracture risk in patients unable to move a limb actively themselves.', 'Rehabilitation & Mobilization', '🏃', true),
(3836, 'Pressure Injury Prevention', 'AI Practice Question', 'To help prevent pressure injuries, immobile patients should generally be repositioned at least every:', '["30 minutes","2 hours","8 hours","24 hours"]'::jsonb, 1, 'Repositioning at least every 2 hours is a standard recommendation to relieve sustained pressure over bony prominences and reduce pressure injury risk, though individualised schedules may vary.', 'Rehabilitation & Mobilization', '🏃', true),
(3837, 'Contracture Prevention', 'AI Practice Question', 'Splinting a limb in a functional position for an immobile patient primarily helps to:', '["Cause muscle wasting","Prevent joint contractures","Increase spasticity","Replace the need for physiotherapy entirely"]'::jsonb, 1, 'Proper splinting maintains joints in a functional position, helping to prevent contractures from prolonged abnormal positioning in immobile patients.', 'Rehabilitation & Mobilization', '🏃', true),
(3838, 'DVT Prevention', 'AI Practice Question', 'Along with pharmacological prophylaxis, mechanical measures such as sequential compression devices help prevent DVT primarily by:', '["Increasing venous stasis","Promoting venous return and reducing venous stasis in the legs","Directly dissolving existing clots","Replacing the need for mobilisation"]'::jsonb, 1, 'Sequential compression devices mechanically promote venous return and reduce venous stasis, complementing pharmacological prophylaxis and mobilisation in DVT prevention.', 'Rehabilitation & Mobilization', '🏃', true),
(3839, 'Functional Assessment', 'AI Practice Question', 'The Functional Independence Measure (FIM) is used to assess:', '["Cardiac risk before surgery","A patient''s level of disability and independence in performing daily activities","Renal function","Coagulation status"]'::jsonb, 1, 'The FIM assesses the degree of assistance a patient requires across physical and cognitive domains of daily function, commonly used in rehabilitation settings to track progress.', 'Rehabilitation & Mobilization', '🏃', true),
(3840, 'Multidisciplinary Rehabilitation', 'AI Practice Question', 'An effective ICU/post-ICU rehabilitation plan typically involves collaboration among:', '["Nursing staff only","Nurses, physiotherapists, occupational therapists, and physicians working together","Only the attending physician","Family members exclusively, without clinical staff"]'::jsonb, 1, 'Comprehensive rehabilitation draws on a multidisciplinary team — nursing, physiotherapy, occupational therapy, and medicine — to address the physical, functional, and psychological needs of recovering patients.', 'Rehabilitation & Mobilization', '🏃', true),
(3841, 'Post-Stroke Rehabilitation', 'AI Practice Question', 'Early mobilisation after an ischaemic stroke, once medically stable, is associated with:', '["Worse functional outcomes in all cases","Improved functional recovery when appropriately timed and monitored","No role in stroke recovery","Increased haemorrhage risk regardless of timing"]'::jsonb, 1, 'When appropriately timed and monitored, early mobilisation after stroke supports better functional recovery, though very early aggressive mobilisation protocols require careful patient selection.', 'Rehabilitation & Mobilization', '🏃', true),
(3842, 'Functional Assessment Tools', 'AI Practice Question', 'The Barthel Index is primarily used to measure:', '["Level of consciousness","A patient''s independence in activities of daily living","Nutritional status","Pain severity"]'::jsonb, 1, 'The Barthel Index scores a patient''s ability to independently perform activities of daily living such as feeding, bathing, and mobility.', 'Rehabilitation & Mobilization', '🏃', true),
(3843, 'Foot Drop Prevention', 'AI Practice Question', 'Foot drop in an immobile patient can be prevented by:', '["Prolonged plantar flexion positioning","Maintaining the foot in a neutral position, such as with supportive footwear or a footboard","Avoiding any ankle support","Restricting all leg movement"]'::jsonb, 1, 'Maintaining the ankle in a neutral (dorsiflexed) position with supportive devices helps prevent foot drop from prolonged plantar flexion positioning.', 'Rehabilitation & Mobilization', '🏃', true),
(3844, 'Chest Physiotherapy', 'AI Practice Question', 'Chest physiotherapy techniques such as percussion and postural drainage primarily aim to:', '["Increase secretion retention","Mobilise and clear pulmonary secretions","Replace the need for suctioning entirely","Reduce lung volumes"]'::jsonb, 1, 'Chest physiotherapy techniques help loosen and mobilise retained pulmonary secretions, facilitating their clearance via coughing or suctioning.', 'Rehabilitation & Mobilization', '🏃', true),
(3845, 'Discharge Planning', 'AI Practice Question', 'Effective discharge planning for a rehabilitation patient should begin:', '["Only on the day of discharge","Early during the hospital stay, involving the patient, family, and multidisciplinary team","After the patient has already left the facility","Without involving the patient''s family"]'::jsonb, 1, 'Discharge planning is most effective when started early in the admission, coordinated across the multidisciplinary team, and involves the patient and family in goal-setting.', 'Rehabilitation & Mobilization', '🏃', true),
(3846, 'Progressive Mobility', 'AI Practice Question', 'A typical progressive mobility protocol in critical care advances through stages such as:', '["Immediate standing and walking with no intermediate steps","Passive range of motion, dangling at the edge of the bed, sitting, then standing/ambulating","Only bed rest until full recovery","Random, unstructured activity"]'::jsonb, 1, 'Progressive mobility protocols advance patients stepwise — from passive ROM and bed exercises, to dangling, sitting, standing, and eventually ambulating — as tolerated and haemodynamically stable.', 'Rehabilitation & Mobilization', '🏃', true),
(3847, 'Fall Risk Assessment', 'AI Practice Question', 'Before mobilising a post-operative or critically ill patient for the first time, the nurse should first:', '["Skip any assessment and proceed directly to ambulation","Assess haemodynamic stability, fall risk, and any lines/tubes that need securing","Remove all monitoring equipment","Wait until the patient requests it"]'::jsonb, 1, 'A pre-mobilisation assessment of vital sign stability, fall risk, and safe management of lines/tubes/drains helps ensure the first mobilisation attempt is safe.', 'Rehabilitation & Mobilization', '🏃', true),
(3848, 'Hand Hygiene', 'AI Practice Question', 'The WHO ''My 5 Moments for Hand Hygiene'' includes performing hand hygiene:', '["Only after touching a patient","Before patient contact, before an aseptic task, after body fluid exposure risk, after patient contact, and after touching patient surroundings","Only once per shift","Only when visibly soiled"]'::jsonb, 1, 'The WHO''s 5 Moments framework specifies five key points during patient care where hand hygiene should occur to interrupt pathogen transmission.', 'Infection Prevention', '🦠', true),
(3849, 'VAP Bundle', 'AI Practice Question', 'A core component of the ventilator-associated pneumonia (VAP) prevention bundle is:', '["Keeping the head of bed flat at 0 degrees","Elevating the head of bed to 30–45 degrees","Avoiding oral care to reduce disruption","Continuous heavy sedation"]'::jsonb, 1, 'Elevating the head of bed 30–45 degrees reduces aspiration risk and is a core element of the VAP prevention bundle, alongside daily sedation vacation and oral care.', 'Infection Prevention', '🦠', true),
(3850, 'CLABSI Bundle', 'AI Practice Question', 'Central line-associated bloodstream infection (CLABSI) prevention bundles emphasise:', '["Minimal barrier precautions during insertion","Maximal sterile barrier precautions and chlorhexidine skin antisepsis during insertion","Leaving dressings unchanged indefinitely","Avoiding daily line necessity review"]'::jsonb, 1, 'CLABSI bundles include maximal sterile barrier precautions, chlorhexidine skin prep, optimal catheter site selection, and daily review of line necessity.', 'Infection Prevention', '🦠', true),
(3851, 'CAUTI Prevention', 'AI Practice Question', 'The most effective single strategy to reduce catheter-associated urinary tract infection (CAUTI) is:', '["Routine catheter irrigation","Minimising catheter use and removing catheters as soon as clinically appropriate","Changing the catheter daily regardless of need","Disconnecting the closed drainage system frequently"]'::jsonb, 1, 'Limiting indwelling catheter use and prompt removal once no longer clinically indicated is the most effective strategy for reducing CAUTI, alongside maintaining a closed drainage system.', 'Infection Prevention', '🦠', true),
(3852, 'Contact Precautions', 'AI Practice Question', 'Contact precautions (gown and gloves) are indicated for a patient colonised or infected with:', '["Influenza","MRSA or C. difficile","Tuberculosis","Chickenpox"]'::jsonb, 1, 'Contact precautions are used for organisms spread by direct or indirect contact, such as MRSA and C. difficile, requiring gown and gloves for patient contact.', 'Infection Prevention', '🦠', true),
(3853, 'Airborne Precautions', 'AI Practice Question', 'Airborne precautions, including use of an N95 respirator, are required for suspected:', '["Seasonal influenza","Pulmonary tuberculosis or measles","MRSA wound infection","Norovirus gastroenteritis"]'::jsonb, 1, 'Airborne precautions with an N95 or higher respirator and negative pressure room are required for pathogens spread via small airborne particles, such as TB and measles.', 'Infection Prevention', '🦠', true),
(3854, 'Droplet Precautions', 'AI Practice Question', 'Droplet precautions, typically requiring a surgical mask, are appropriate for a patient with:', '["Active pulmonary tuberculosis","Influenza","MRSA colonisation","C. difficile infection"]'::jsonb, 1, 'Droplet precautions with a surgical mask are used for pathogens spread via larger respiratory droplets over short distances, such as influenza.', 'Infection Prevention', '🦠', true),
(3855, 'PPE Donning Order', 'AI Practice Question', 'The generally recommended sequence for donning PPE is:', '["Gloves, gown, mask, eye protection","Gown, mask/respirator, eye protection, gloves","Mask, gloves, gown, eye protection","Eye protection, gloves, gown, mask"]'::jsonb, 1, 'Standard donning sequence is gown first, then mask/respirator, then eye protection, and gloves last, ensuring gloves cover the gown cuffs.', 'Infection Prevention', '🦠', true),
(3856, 'PPE Doffing Order', 'AI Practice Question', 'When removing (doffing) PPE, the item removed first is typically the:', '["Gloves, since they are the most contaminated","Respirator/mask","Gown","Eye protection"]'::jsonb, 0, 'Gloves are removed first since they are usually the most heavily contaminated item, followed by careful removal of the remaining PPE to avoid self-contamination, with the mask/respirator typically removed last.', 'Infection Prevention', '🦠', true),
(3857, 'Sterilization vs Disinfection', 'AI Practice Question', 'The key difference between sterilisation and disinfection is that sterilisation:', '["Only reduces the number of vegetative bacteria","Destroys all forms of microbial life, including spores","Is only used on skin","Requires no special equipment"]'::jsonb, 1, 'Sterilisation eliminates all microorganisms including bacterial spores, whereas disinfection reduces pathogens but may not eliminate all spores.', 'Infection Prevention', '🦠', true),
(3858, 'Antibiotic Stewardship', 'AI Practice Question', 'The primary goal of an antibiotic stewardship programme is to:', '["Maximise antibiotic use for all patients","Optimise antibiotic selection, dosing, and duration to improve outcomes and limit resistance","Eliminate the use of antibiotics entirely","Reduce the role of pharmacists in prescribing decisions"]'::jsonb, 1, 'Antibiotic stewardship programmes aim to ensure the right drug, dose, and duration for each patient, improving outcomes while reducing the development of antimicrobial resistance.', 'Infection Prevention', '🦠', true),
(3859, 'Needle-Stick Injury', 'AI Practice Question', 'The immediate first step after a needle-stick injury is to:', '["Ignore it if the source patient appears healthy","Wash the area with soap and water and report the exposure per protocol","Apply a tourniquet","Wait 24 hours before taking any action"]'::jsonb, 1, 'Immediate washing of the wound with soap and water, followed by prompt reporting and risk assessment/prophylaxis per institutional protocol, is the recommended first response to a needle-stick injury.', 'Infection Prevention', '🦠', true),
(3860, 'Surgical Site Infection Prevention', 'AI Practice Question', 'Prophylactic antibiotics for surgical site infection prevention are most effective when administered:', '["More than 24 hours after surgery","Within about 60 minutes before surgical incision","Only after signs of infection appear","Never, as they provide no benefit"]'::jsonb, 1, 'Prophylactic antibiotics are typically given within about 60 minutes before incision to achieve adequate tissue concentration during the period of highest contamination risk.', 'Infection Prevention', '🦠', true),
(3861, 'Central Line Dressing', 'AI Practice Question', 'Transparent central line dressings are generally changed at intervals of approximately:', '["Every 24 hours regardless of condition","Every 5–7 days, or sooner if soiled, loose, or damp","Only when the line is removed","Every 30 days"]'::jsonb, 1, 'Transparent semi-permeable dressings are typically changed every 5–7 days, or immediately if they become soiled, loose, or damp, to reduce CLABSI risk.', 'Infection Prevention', '🦠', true),
(3862, 'Hand Hygiene Method Selection', 'AI Practice Question', 'For a patient with active Clostridioides difficile infection, hand hygiene should be performed with:', '["Alcohol-based hand rub only","Soap and water, since alcohol-based rubs do not reliably kill C. difficile spores","No hand hygiene is needed if gloves were worn","Hand sanitiser gel exclusively"]'::jsonb, 1, 'C. difficile forms spores that are resistant to alcohol-based hand rubs, so soap and water with mechanical friction is required to physically remove spores.', 'Infection Prevention', '🦠', true),
(3863, 'AKI Staging', 'AI Practice Question', 'The KDIGO criteria for staging acute kidney injury are based primarily on changes in:', '["Blood pressure and heart rate","Serum creatinine and urine output","Serum sodium only","Haemoglobin level"]'::jsonb, 1, 'KDIGO AKI staging uses the magnitude of serum creatinine rise and the degree/duration of reduced urine output to classify AKI severity.', 'Renal & Fluid Balance', '💧', true),
(3864, 'Renal Replacement Therapy', 'AI Practice Question', 'Continuous renal replacement therapy (CRRT) is often preferred over intermittent haemodialysis in haemodynamically unstable ICU patients because it:', '["Removes fluid and solutes more slowly and continuously, improving haemodynamic tolerance","Is completed within 30 minutes","Requires no vascular access","Cannot be used in AKI"]'::jsonb, 0, 'CRRT removes fluid and solutes gradually over 24 hours, causing less haemodynamic stress than the more rapid intermittent haemodialysis, making it better tolerated in unstable patients.', 'Renal & Fluid Balance', '💧', true),
(3865, 'Dialysis Complications', 'AI Practice Question', 'Dialysis disequilibrium syndrome results from:', '["Too slow a rate of solute removal","Rapid removal of solutes causing a cerebral osmotic gradient and cerebral oedema","Excessive potassium intake","Underdialysis over months"]'::jsonb, 1, 'Rapid correction of uraemia during dialysis can create an osmotic gradient causing water to shift into brain cells, leading to cerebral oedema and the symptoms of disequilibrium syndrome.', 'Renal & Fluid Balance', '💧', true),
(3866, 'Hyperkalaemia Management', 'AI Practice Question', 'In severe hyperkalaemia with ECG changes, calcium gluconate is administered primarily to:', '["Lower the serum potassium level","Stabilise the cardiac cell membrane and reduce arrhythmia risk","Treat metabolic acidosis","Increase urine output"]'::jsonb, 1, 'Calcium gluconate does not lower potassium but stabilises the myocardial cell membrane, reducing the risk of life-threatening arrhythmias while other measures lower the potassium level.', 'Renal & Fluid Balance', '💧', true),
(3867, 'Fluid Overload', 'AI Practice Question', 'Clinical signs of fluid overload include:', '["Flat neck veins and dry mucous membranes","Jugular venous distension, peripheral oedema, and crackles on lung auscultation","Hypotension and tachycardia from hypovolaemia","Decreased body weight"]'::jsonb, 1, 'Fluid overload presents with JVD, dependent/peripheral oedema, pulmonary crackles, and often weight gain, reflecting excess fluid in the vascular and interstitial spaces.', 'Renal & Fluid Balance', '💧', true),
(3868, 'Oliguria', 'AI Practice Question', 'Oliguria in an adult is generally defined as urine output less than:', '["3 mL/kg/hr","0.5 mL/kg/hr","5 mL/kg/hr","10 mL/kg/hr"]'::jsonb, 1, 'Oliguria is typically defined as urine output under 0.5 mL/kg/hr, a key clinical indicator of reduced renal perfusion or function.', 'Renal & Fluid Balance', '💧', true),
(3869, 'Nephrotoxic Drugs', 'AI Practice Question', 'Which class of medication is well recognised as nephrotoxic and should be used cautiously in renal impairment?', '["Beta-blockers","Aminoglycoside antibiotics","Antihistamines","Proton pump inhibitors"]'::jsonb, 1, 'Aminoglycosides (e.g. gentamicin) are well-established nephrotoxins, along with NSAIDs and iodinated contrast media, requiring cautious dosing and monitoring in patients with renal impairment.', 'Renal & Fluid Balance', '💧', true),
(3870, 'AV Fistula Assessment', 'AI Practice Question', 'Assessment of a functioning arteriovenous (AV) fistula should include palpating for a:', '["Bounding pulse only","Thrill and auscultating for a bruit","Cold, pale extremity","Absent pulse distally as a normal finding"]'::jsonb, 1, 'A patent AV fistula produces a palpable thrill and an audible bruit from turbulent blood flow; absence of either suggests possible thrombosis requiring urgent evaluation.', 'Renal & Fluid Balance', '💧', true),
(3871, 'Peritoneal Dialysis', 'AI Practice Question', 'A major complication specific to peritoneal dialysis is:', '["Air embolism","Peritonitis","Dialysis disequilibrium syndrome exclusively","Arteriovenous fistula thrombosis"]'::jsonb, 1, 'Peritonitis, introduced via the peritoneal catheter, is a major and common complication specific to peritoneal dialysis, presenting with cloudy effluent, abdominal pain, and fever.', 'Renal & Fluid Balance', '💧', true),
(3872, 'AKI Classification', 'AI Practice Question', 'Acute kidney injury caused by renal artery stenosis reducing blood flow to the kidney is classified as:', '["Prerenal","Intrinsic (renal)","Postrenal","Not a cause of AKI"]'::jsonb, 0, 'Prerenal AKI results from reduced blood flow reaching the kidneys (e.g. hypovolaemia, hypotension, renal artery stenosis) before intrinsic kidney damage occurs.', 'Renal & Fluid Balance', '💧', true),
(3873, 'Fluid Restriction', 'AI Practice Question', 'Fluid restriction is often prescribed in advanced renal failure primarily to:', '["Increase urine output","Prevent fluid overload and its complications, such as pulmonary oedema","Lower blood glucose","Increase serum sodium rapidly"]'::jsonb, 1, 'With reduced ability to excrete fluid, restricting intake helps prevent fluid overload and complications like pulmonary oedema and hypertension in advanced renal failure.', 'Renal & Fluid Balance', '💧', true),
(3874, 'Metabolic Acidosis in Renal Failure', 'AI Practice Question', 'Metabolic acidosis in chronic kidney disease primarily results from the kidney''s reduced ability to:', '["Reabsorb glucose","Excrete hydrogen ions and regenerate bicarbonate","Produce erythropoietin","Filter red blood cells"]'::jsonb, 1, 'Failing kidneys lose the ability to adequately excrete the daily hydrogen ion load and regenerate bicarbonate, leading to a normal-to-high anion gap metabolic acidosis.', 'Renal & Fluid Balance', '💧', true),
(3875, 'Erythropoietin', 'AI Practice Question', 'Erythropoietin therapy is used in chronic kidney disease to treat:', '["Hyperkalaemia","Anaemia due to reduced renal erythropoietin production","Fluid overload","Metabolic acidosis"]'::jsonb, 1, 'Failing kidneys produce less erythropoietin, contributing to anaemia of chronic kidney disease; recombinant erythropoietin stimulates red blood cell production.', 'Renal & Fluid Balance', '💧', true),
(3876, 'Contrast-Induced Nephropathy', 'AI Practice Question', 'A key preventive measure against contrast-induced nephropathy in at-risk patients is:', '["Fluid restriction before the procedure","Adequate periprocedural IV hydration","Withholding all medications","Administering high-dose NSAIDs beforehand"]'::jsonb, 1, 'Adequate IV hydration before and after contrast administration is a primary strategy to reduce the risk of contrast-induced nephropathy in at-risk patients.', 'Renal & Fluid Balance', '💧', true),
(3877, 'Fluid Balance Monitoring', 'AI Practice Question', 'Daily weight monitoring in a patient with renal or cardiac fluid balance concerns is valuable because:', '["It has no correlation with fluid status","Rapid weight change closely reflects fluid gain or loss","It replaces the need for intake/output charting entirely","It only reflects nutritional status"]'::jsonb, 1, 'Short-term weight changes closely track fluid retention or loss (1kg approximates 1L of fluid), making daily weights a sensitive complement to intake/output charting.', 'Renal & Fluid Balance', '💧', true),
(3878, 'Hemorrhagic Shock Classification', 'AI Practice Question', 'Class II haemorrhagic shock (approximately 15–30% blood loss) typically presents with:', '["Normal heart rate and blood pressure","Tachycardia with a still-normal or slightly decreased blood pressure","Profound hypotension and unconsciousness","Bradycardia and hypertension"]'::jsonb, 1, 'Class II haemorrhage produces compensatory tachycardia and narrowed pulse pressure while systolic blood pressure may still appear relatively preserved due to compensatory vasoconstriction.', 'Shock & Haemorrhage', '⚡', true),
(3879, 'Mean Arterial Pressure', 'AI Practice Question', 'Mean arterial pressure (MAP) can be estimated using the formula:', '["MAP = SBP + DBP","MAP = DBP + 1/3(SBP - DBP)","MAP = SBP - DBP","MAP = SBP x DBP"]'::jsonb, 1, 'MAP is approximately diastolic blood pressure plus one-third of the pulse pressure (SBP minus DBP), reflecting average arterial pressure during the cardiac cycle.', 'Shock & Haemorrhage', '⚡', true),
(3880, 'Types of Shock', 'AI Practice Question', 'Distributive shock, such as septic or anaphylactic shock, is primarily characterised by:', '["Pump failure of the heart","Widespread vasodilation and maldistribution of blood flow","Mechanical obstruction of blood flow","Loss of intravascular volume from haemorrhage"]'::jsonb, 1, 'Distributive shock results from excessive vasodilation and abnormal distribution of blood flow, reducing effective circulating volume despite normal or increased total blood volume.', 'Shock & Haemorrhage', '⚡', true),
(3881, 'Septic Shock Management', 'AI Practice Question', 'The first-line vasopressor recommended in septic shock, according to major guidelines, is:', '["Dopamine","Norepinephrine","Phenylephrine as first choice","Vasopressin as first choice"]'::jsonb, 1, 'Norepinephrine is recommended as the first-line vasopressor in septic shock due to its favourable balance of vasoconstriction with limited chronotropic/arrhythmic effects.', 'Shock & Haemorrhage', '⚡', true),
(3882, 'Compensatory Mechanisms', 'AI Practice Question', 'Early compensatory responses to hypovolaemic shock include:', '["Bradycardia and vasodilation","Tachycardia and peripheral vasoconstriction","Decreased respiratory rate","Increased urine output"]'::jsonb, 1, 'The sympathetic nervous system responds to reduced circulating volume with tachycardia and peripheral vasoconstriction to help maintain blood pressure and perfusion to vital organs.', 'Shock & Haemorrhage', '⚡', true),
(3883, 'Permissive Hypotension', 'AI Practice Question', 'Permissive hypotension in early trauma resuscitation (before definitive haemorrhage control) aims to:', '["Normalise blood pressure fully with aggressive fluids","Avoid excessive fluid administration that could dislodge clots and worsen bleeding","Increase blood pressure well above baseline","Eliminate the need for blood transfusion"]'::jsonb, 1, 'Permissive hypotension targets a lower-than-normal blood pressure to avoid disrupting early clot formation with aggressive fluid resuscitation before the bleeding source is controlled.', 'Shock & Haemorrhage', '⚡', true),
(3884, 'Massive Transfusion Protocol', 'AI Practice Question', 'A commonly used massive transfusion protocol ratio for packed red cells, plasma, and platelets is approximately:', '["1:1:1","10:1:1","1:10:1","5:5:1"]'::jsonb, 0, 'Many massive transfusion protocols use a balanced ratio approximating 1:1:1 of packed red cells, plasma, and platelets to mimic whole blood and reduce dilutional coagulopathy.', 'Shock & Haemorrhage', '⚡', true),
(3885, 'Anaphylactic Shock', 'AI Practice Question', 'The first-line treatment for anaphylactic shock is:', '["Diphenhydramine alone","Intramuscular epinephrine","Oral corticosteroids","Beta-blockers"]'::jsonb, 1, 'Intramuscular epinephrine is the first-line, life-saving treatment for anaphylaxis, addressing both the vasodilation and bronchoconstriction of the reaction; antihistamines and steroids are adjuncts.', 'Shock & Haemorrhage', '⚡', true),
(3886, 'Cardiogenic Shock', 'AI Practice Question', 'Haemodynamic monitoring in cardiogenic shock classically shows:', '["Low pulmonary capillary wedge pressure and high cardiac output","High pulmonary capillary wedge pressure and low cardiac output","Normal filling pressures with high cardiac output","Low systemic vascular resistance"]'::jsonb, 1, 'Cardiogenic shock reflects pump failure, producing elevated filling pressures (high PCWP) as blood backs up while cardiac output falls due to poor contractility.', 'Shock & Haemorrhage', '⚡', true),
(3887, 'Obstructive Shock', 'AI Practice Question', 'Obstructive shock can result from conditions such as:', '["Sepsis and anaphylaxis","Cardiac tamponade, tension pneumothorax, and massive pulmonary embolism","Haemorrhage alone","Spinal cord injury alone"]'::jsonb, 1, 'Obstructive shock occurs when a mechanical obstruction impairs cardiac filling or output, as seen in cardiac tamponade, tension pneumothorax, and massive PE.', 'Shock & Haemorrhage', '⚡', true),
(3888, 'Resuscitation Monitoring', 'AI Practice Question', 'Trending serial lactate levels during shock resuscitation is useful because:', '["Lactate clearance correlates with improving tissue perfusion","Lactate has no relationship to perfusion status","It replaces the need for vital sign monitoring","It only reflects liver function"]'::jsonb, 0, 'Improving (clearing) lactate levels over serial measurements suggest resuscitation is restoring adequate tissue perfusion, making it a useful trend marker during shock management.', 'Shock & Haemorrhage', '⚡', true),
(3889, 'Capillary Refill', 'AI Practice Question', 'A prolonged capillary refill time (greater than 2–3 seconds) in a shocked patient suggests:', '["Adequate peripheral perfusion","Reduced peripheral perfusion","Only a cold ambient room temperature, never clinical significance","Improved cardiac output"]'::jsonb, 1, 'Delayed capillary refill reflects peripheral vasoconstriction and reduced perfusion, a simple bedside sign consistent with shock states, though ambient temperature can also affect it.', 'Shock & Haemorrhage', '⚡', true),
(3890, 'Vasoactive Drugs', 'AI Practice Question', 'Norepinephrine''s primary haemodynamic action is:', '["Pure vasodilation","Potent vasoconstriction via alpha-1 receptor stimulation, with modest inotropic effect","Bronchodilation only","Diuresis"]'::jsonb, 1, 'Norepinephrine acts predominantly on alpha-1 receptors to cause vasoconstriction, raising blood pressure, with some beta-1 mediated inotropic effect, making it the first-line vasopressor in septic shock.', 'ICU Pharmacology', '💊', true),
(3891, 'Vasoactive Drugs', 'AI Practice Question', 'Dobutamine is primarily used in critical care for its:', '["Vasoconstrictor effect","Inotropic effect, improving cardiac contractility and output","Antiarrhythmic properties","Diuretic effect"]'::jsonb, 1, 'Dobutamine is a beta-1 agonist with predominant inotropic (and mild vasodilatory) effects, used to improve cardiac output in cardiogenic shock or low-output heart failure.', 'ICU Pharmacology', '💊', true),
(3892, 'Vasoactive Drugs', 'AI Practice Question', 'Vasopressin is sometimes added in septic shock management primarily to:', '["Replace norepinephrine entirely","Allow a norepinephrine-sparing effect by acting on a different receptor pathway","Treat bradycardia","Lower blood pressure"]'::jsonb, 1, 'Vasopressin acts on V1 receptors, a pathway distinct from catecholamines, and is often added as a second agent to help reduce the required norepinephrine dose in refractory septic shock.', 'ICU Pharmacology', '💊', true),
(3893, 'Sedation', 'AI Practice Question', 'Propofol infusion syndrome is a rare but serious complication associated with:', '["Short-term, low-dose propofol use","Prolonged, high-dose propofol infusion","Dexmedetomidine use","Fentanyl use"]'::jsonb, 1, 'Propofol infusion syndrome, involving metabolic acidosis, rhabdomyolysis, and cardiac failure, is associated with prolonged high-dose propofol infusions, particularly in critically ill patients.', 'ICU Pharmacology', '💊', true),
(3894, 'Sedation', 'AI Practice Question', 'A key advantage of dexmedetomidine over benzodiazepine sedation in the ICU is that dexmedetomidine:', '["Causes significant respiratory depression","Provides sedation with minimal respiratory depression, allowing patients to remain arousable","Cannot be used in mechanically ventilated patients","Has no analgesic properties at all"]'::jsonb, 1, 'Dexmedetomidine, an alpha-2 agonist, provides cooperative sedation with minimal respiratory depression, distinguishing it from benzodiazepines and supporting lighter sedation protocols.', 'ICU Pharmacology', '💊', true),
(3895, 'Analgesia', 'AI Practice Question', 'Fentanyl is often preferred over morphine in patients with renal impairment because fentanyl:', '["Has active metabolites that accumulate in renal failure","Has no clinically significant active metabolites that accumulate in renal failure","Cannot be given intravenously","Has a much longer half-life"]'::jsonb, 1, 'Unlike morphine, which has active metabolites that can accumulate and cause toxicity in renal failure, fentanyl lacks clinically significant active metabolites, making it a safer choice in renal impairment.', 'ICU Pharmacology', '💊', true),
(3896, 'Neuromuscular Blockade Monitoring', 'AI Practice Question', 'Train-of-four monitoring is used during neuromuscular blockade to:', '["Measure blood pressure","Assess the depth of neuromuscular blockade and guide dosing","Monitor cardiac rhythm","Assess sedation depth"]'::jsonb, 1, 'Train-of-four peripheral nerve stimulation assesses the degree of neuromuscular blockade by counting twitch responses, helping titrate paralytic dosing and confirm adequate reversal.', 'ICU Pharmacology', '💊', true),
(3897, 'Anticoagulant Reversal', 'AI Practice Question', 'The specific reversal agent for unfractionated heparin is:', '["Vitamin K","Protamine sulfate","Fresh frozen plasma only","Dantrolene"]'::jsonb, 1, 'Protamine sulfate binds and neutralises heparin, providing rapid reversal of its anticoagulant effect.', 'ICU Pharmacology', '💊', true),
(3898, 'Anticoagulant Reversal', 'AI Practice Question', 'Reversal of warfarin''s anticoagulant effect for significant bleeding may involve:', '["Protamine sulfate","Vitamin K and prothrombin complex concentrate (PCC) or fresh frozen plasma","Naloxone","Dantrolene"]'::jsonb, 1, 'Warfarin reversal for serious bleeding typically uses vitamin K to restore clotting factor synthesis, combined with PCC or FFP for immediate factor replacement.', 'ICU Pharmacology', '💊', true),
(3899, 'Antiarrhythmics', 'AI Practice Question', 'Amiodarone therapy requires monitoring of which organs due to potential toxicity?', '["Thyroid, liver, and lungs","Only the kidneys","Only the pancreas","Only the skin"]'::jsonb, 0, 'Amiodarone can cause thyroid dysfunction, hepatotoxicity, and pulmonary fibrosis with long-term use, requiring periodic monitoring of thyroid function, liver enzymes, and pulmonary status.', 'ICU Pharmacology', '💊', true),
(3900, 'Opioid Reversal', 'AI Practice Question', 'A key nursing consideration when administering naloxone to reverse opioid overdose is that:', '["Its effect lasts longer than most opioids, so no monitoring is needed","Its duration of action may be shorter than the opioid, risking re-sedation and requiring close monitoring","It has no risk of precipitating withdrawal","It should be given regardless of respiratory status"]'::jsonb, 1, 'Naloxone''s duration of action can be shorter than that of the opioid being reversed, so patients require close monitoring for re-sedation/re-narcosis as the naloxone wears off.', 'ICU Pharmacology', '💊', true),
(3901, 'Benzodiazepine Reversal', 'AI Practice Question', 'Flumazenil, used to reverse benzodiazepine sedation, should be used cautiously in patients who:', '["Have never taken benzodiazepines","Are chronic benzodiazepine users, due to seizure risk","Are undergoing routine anaesthesia reversal only","Have normal renal function"]'::jsonb, 1, 'In chronic benzodiazepine users, flumazenil can precipitate acute withdrawal and seizures by abruptly reversing tolerance-related GABA receptor effects.', 'ICU Pharmacology', '💊', true),
(3902, 'Insulin Infusion', 'AI Practice Question', 'Patients on a continuous insulin infusion in the ICU require blood glucose monitoring at a frequency of approximately:', '["Once every 24 hours","Hourly, or per institutional protocol","Once weekly","Only if symptomatic"]'::jsonb, 1, 'Continuous insulin infusions carry hypoglycaemia risk and require frequent (commonly hourly) blood glucose checks to guide safe titration.', 'ICU Pharmacology', '💊', true),
(3903, 'Vasoactive Drugs', 'AI Practice Question', 'Dopamine''s haemodynamic effect varies by dose, with higher doses primarily producing:', '["Renal vasodilation only","Alpha-adrenergic vasoconstriction","Bronchodilation","Pure beta-2 effects"]'::jsonb, 1, 'At higher doses, dopamine increasingly stimulates alpha-adrenergic receptors, producing vasoconstriction, while lower doses favour dopaminergic and beta-1 effects.', 'ICU Pharmacology', '💊', true),
(3904, 'Diuretics', 'AI Practice Question', 'When administering furosemide, the nurse should closely monitor for:', '["Hyperkalaemia","Hypokalaemia and other electrolyte disturbances","Hypoglycaemia specifically caused by the drug","Bradycardia as the primary risk"]'::jsonb, 1, 'Furosemide, a loop diuretic, promotes potassium (and other electrolyte) losses in the urine, making electrolyte monitoring essential during therapy.', 'ICU Pharmacology', '💊', true),
(3905, 'Informed Consent', 'AI Practice Question', 'Valid informed consent requires that the patient:', '["Simply signs a form without explanation","Receives adequate information, understands it, and voluntarily agrees without coercion","Is sedated at the time of signing","Delegates the decision to hospital staff by default"]'::jsonb, 1, 'True informed consent requires disclosure of relevant information, patient understanding, and a voluntary decision free from coercion — not merely a signature.', 'Ethics, Law & Management', '⚖️', true),
(3906, 'Advance Directives', 'AI Practice Question', 'An advance directive is a document that:', '["Is only valid after the patient''s death","Expresses a patient''s wishes for future medical care if they become unable to decide for themselves","Can only be created by a physician","Overrides all patient autonomy while the patient is conscious"]'::jsonb, 1, 'Advance directives allow a competent patient to document their preferences for future care in the event that they later lose capacity to make decisions.', 'Ethics, Law & Management', '⚖️', true),
(3907, 'DNR Orders', 'AI Practice Question', 'A Do Not Resuscitate (DNR) order specifically means that:', '["All medical treatment, including pain management, should be withheld","Cardiopulmonary resuscitation will not be performed, but other appropriate care continues","The patient is no longer a candidate for any nursing care","The family''s wishes are automatically overridden"]'::jsonb, 1, 'A DNR order applies specifically to withholding CPR in the event of cardiac or respiratory arrest — it does not mean withholding other appropriate treatment, comfort care, or nursing interventions.', 'Ethics, Law & Management', '⚖️', true),
(3908, 'Negligence', 'AI Practice Question', 'The four elements that must be proven to establish nursing negligence are:', '["Consent, capacity, competence, and cost","Duty, breach of duty, causation, and damages","Autonomy, beneficence, non-maleficence, and justice","Assessment, diagnosis, planning, and evaluation"]'::jsonb, 1, 'Legal negligence requires demonstrating a duty of care existed, that duty was breached, the breach caused harm, and measurable damages resulted.', 'Ethics, Law & Management', '⚖️', true),
(3909, 'Confidentiality', 'AI Practice Question', 'Patient confidentiality may be ethically breached when:', '["A colleague is simply curious","There is a credible risk of serious harm to the patient or identifiable third parties","A family member requests information without consent","It is more convenient for staff"]'::jsonb, 1, 'Confidentiality can be ethically and legally breached in specific circumstances, such as credible threat of serious harm to the patient or an identifiable third party, or as required by law.', 'Ethics, Law & Management', '⚖️', true),
(3910, 'Delegation', 'AI Practice Question', 'The ''five rights of delegation'' include the right task, right circumstance, right person, right direction/communication, and right:', '["Reimbursement","Supervision/evaluation","Diagnosis","Documentation software"]'::jsonb, 1, 'The five rights of delegation are right task, right circumstance, right person, right direction/communication, and right supervision/evaluation of the delegated task.', 'Ethics, Law & Management', '⚖️', true),
(3911, 'Incident Reporting', 'AI Practice Question', 'The primary purpose of incident (adverse event) reporting in healthcare is to:', '["Assign blame and discipline individual staff","Identify system issues and improve patient safety through learning","Satisfy insurance requirements only","Reduce documentation workload"]'::jsonb, 1, 'Incident reporting systems are intended to be non-punitive tools for identifying systemic causes of errors and near-misses, driving quality improvement rather than individual blame.', 'Ethics, Law & Management', '⚖️', true),
(3912, 'Scope of Practice', 'AI Practice Question', 'A nurse''s scope of practice is defined by:', '["Personal preference alone","Professional regulatory standards, licensure, education, and institutional policy","Whatever tasks are convenient for the unit","The patient''s request alone"]'::jsonb, 1, 'Scope of practice is determined by nursing regulatory bodies, licensure requirements, educational preparation, and institutional policies — not personal choice or patient request alone.', 'Ethics, Law & Management', '⚖️', true),
(3913, 'Ethical Principles', 'AI Practice Question', 'The ethical principle of autonomy refers to:', '["The healthcare provider''s right to decide for the patient","The patient''s right to make informed decisions about their own care","Equal distribution of resources","Avoiding harm to the patient"]'::jsonb, 1, 'Autonomy is the ethical principle respecting a competent patient''s right to make informed decisions about their own healthcare, even if the provider disagrees.', 'Ethics, Law & Management', '⚖️', true),
(3914, 'Ethical Principles', 'AI Practice Question', 'The difference between beneficence and non-maleficence is that beneficence involves:', '["Avoiding harm, while non-maleficence involves actively doing good","Actively acting to benefit the patient, while non-maleficence involves the duty to avoid causing harm","They are identical concepts","Neither relates to patient care"]'::jsonb, 1, 'Beneficence is the duty to actively act in the patient''s best interest, while non-maleficence (''first, do no harm'') is the duty to avoid causing harm.', 'Ethics, Law & Management', '⚖️', true),
(3915, 'Resource Allocation', 'AI Practice Question', 'The ethical principle of justice, as applied to resource allocation in critical care, refers to:', '["Treating all patients identically regardless of need","Fair and equitable distribution of limited healthcare resources","Prioritising the wealthiest patients","Ignoring resource limitations entirely"]'::jsonb, 1, 'Justice in healthcare ethics concerns the fair, equitable distribution of limited resources such as ICU beds, ventilators, or organs, based on need and ethically defensible criteria.', 'Ethics, Law & Management', '⚖️', true),
(3916, 'Whistleblowing', 'AI Practice Question', 'If a nurse witnesses another staff member committing a serious, unsafe practice violation, the appropriate ethical action is to:', '["Ignore it to avoid conflict","Report it through appropriate institutional and/or regulatory channels","Only discuss it informally with friends","Confront the colleague publicly in front of patients"]'::jsonb, 1, 'Nurses have an ethical and professional obligation to report unsafe or unethical practice through proper channels to protect patient safety, even when this is uncomfortable.', 'Ethics, Law & Management', '⚖️', true),
(3917, 'Anion Gap', 'AI Practice Question', 'The anion gap is primarily used to:', '["Diagnose respiratory failure","Help classify the cause of a metabolic acidosis","Measure oxygenation","Assess renal blood flow"]'::jsonb, 1, 'Calculating the anion gap (Na - [Cl + HCO3]) helps distinguish high anion gap metabolic acidosis (e.g. lactic acidosis, DKA, renal failure) from normal anion gap causes (e.g. diarrhoea, RTA).', 'ABG & Electrolytes', '🩸', true),
(3918, 'Acid-Base Compensation', 'AI Practice Question', 'In chronic respiratory acidosis, the expected renal compensatory response is:', '["Decreased bicarbonate reabsorption","Increased renal bicarbonate reabsorption/generation to raise serum HCO3","Hyperventilation","No compensation occurs"]'::jsonb, 1, 'The kidneys compensate for chronic respiratory acidosis by increasing bicarbonate reabsorption and generation, raising serum HCO3 to help normalise pH over days.', 'ABG & Electrolytes', '🩸', true),
(3919, 'Acid-Base Compensation', 'AI Practice Question', 'The expected respiratory compensation for metabolic alkalosis is:', '["Hyperventilation to blow off more CO2","Hypoventilation, retaining CO2 to help lower pH toward normal","No respiratory change occurs","Immediate renal correction only"]'::jsonb, 1, 'In metabolic alkalosis, the respiratory system compensates by hypoventilating, retaining CO2 to counterbalance the elevated pH — though this compensation is limited by the resulting hypoxaemia drive.', 'ABG & Electrolytes', '🩸', true),
(3920, 'Hypocalcaemia', 'AI Practice Question', 'Chvostek''s and Trousseau''s signs are clinical indicators of:', '["Hyperkalaemia","Hypocalcaemia","Hypernatraemia","Hypomagnesaemia exclusively"]'::jsonb, 1, 'Chvostek''s sign (facial twitching on tapping the facial nerve) and Trousseau''s sign (carpal spasm with blood pressure cuff inflation) are classic bedside indicators of neuromuscular irritability from hypocalcaemia.', 'ABG & Electrolytes', '🩸', true),
(3921, 'Hypercalcaemia', 'AI Practice Question', 'A characteristic ECG change seen in hypercalcaemia is:', '["Prolonged QT interval","Shortened QT interval","Peaked T waves","Widened QRS complex as the primary finding"]'::jsonb, 1, 'Hypercalcaemia classically shortens the QT interval on ECG, in contrast to hypocalcaemia, which prolongs it.', 'ABG & Electrolytes', '🩸', true),
(3922, 'Hypomagnesaemia', 'AI Practice Question', 'Hypomagnesaemia is clinically significant in critical care partly because it:', '["Has no effect on cardiac rhythm","Can cause refractory hypokalaemia and predispose to cardiac arrhythmias","Always causes hypercalcaemia","Only affects bone density"]'::jsonb, 1, 'Low magnesium impairs the renal potassium-sparing mechanism, often causing hypokalaemia that resists correction until magnesium is also replaced, and independently predisposes to arrhythmias such as torsades de pointes.', 'ABG & Electrolytes', '🩸', true),
(3923, 'Hyperphosphataemia', 'AI Practice Question', 'Hyperphosphataemia is a common electrolyte disturbance in patients with:', '["Chronic kidney disease","Diabetes insipidus","Primary hyperaldosteronism","SIADH"]'::jsonb, 0, 'Reduced renal phosphate excretion in chronic kidney disease commonly leads to hyperphosphataemia, which also contributes to secondary hyperparathyroidism and vascular calcification over time.', 'ABG & Electrolytes', '🩸', true),
(3924, 'Mixed Acid-Base Disorders', 'AI Practice Question', 'A patient with a pH within normal range but markedly abnormal PaCO2 and HCO3 values likely has:', '["A single, uncompensated acid-base disorder","A mixed acid-base disorder or full compensation of a chronic disorder","A laboratory error only","Normal acid-base status with no further evaluation needed"]'::jsonb, 1, 'A normal pH with significantly deranged PaCO2 and HCO3 suggests either a mixed acid-base disturbance or complete compensation of a chronic process, warranting careful clinical correlation.', 'ABG & Electrolytes', '🩸', true),
(3925, 'Base Excess', 'AI Practice Question', 'A negative base excess (base deficit) on an ABG indicates:', '["A relative excess of bicarbonate/buffer base, consistent with alkalosis","A relative deficit of buffer base, consistent with a metabolic acidosis component","Normal acid-base status","Respiratory alkalosis specifically"]'::jsonb, 1, 'A negative base excess (base deficit) reflects a relative shortage of buffering base in the blood, indicating a metabolic acidosis component.', 'ABG & Electrolytes', '🩸', true),
(3926, 'Hypokalaemia ECG', 'AI Practice Question', 'Characteristic ECG changes of hypokalaemia include:', '["Peaked T waves and widened QRS","Flattened T waves and prominent U waves","Shortened QT interval","Complete absence of P waves in all cases"]'::jsonb, 1, 'Hypokalaemia classically produces flattened or inverted T waves and prominent U waves on ECG, along with potential ST depression.', 'ABG & Electrolytes', '🩸', true),
(3927, 'Hyperkalaemia ECG', 'AI Practice Question', 'Early ECG changes of hyperkalaemia typically include:', '["Flattened T waves","Tall, peaked T waves","Prolonged QT interval as the earliest change","U waves"]'::jsonb, 1, 'Peaked, tented T waves are typically the earliest ECG change of hyperkalaemia, progressing to PR prolongation, widened QRS, and eventually a sine-wave pattern if untreated.', 'ABG & Electrolytes', '🩸', true),
(3928, 'Winter''s Formula', 'AI Practice Question', 'Winter''s formula is used to determine the expected respiratory compensation for:', '["Respiratory acidosis","A primary metabolic acidosis","Metabolic alkalosis","Respiratory alkalosis"]'::jsonb, 1, 'Winter''s formula predicts the expected PaCO2 compensation for a given bicarbonate level in metabolic acidosis, helping identify a coexisting respiratory disorder if actual PaCO2 deviates from the predicted value.', 'ABG & Electrolytes', '🩸', true),
(3929, 'Parkland Formula', 'AI Practice Question', 'The Parkland formula for burn fluid resuscitation is calculated as:', '["2mL x body weight (kg) x %TBSA burned","4mL x body weight (kg) x %TBSA burned","10mL x body weight (kg) regardless of burn size","1mL x %TBSA burned only"]'::jsonb, 1, 'The Parkland formula estimates 24-hour crystalloid fluid requirements as 4mL x body weight in kg x percentage total body surface area burned, with half given in the first 8 hours from time of injury.', 'Burns & Trauma', '🔥', true),
(3930, 'Burn Depth Classification', 'AI Practice Question', 'A full-thickness (third-degree) burn is characterised by:', '["Painful, red, blistered skin","Dry, leathery, often painless skin due to destroyed nerve endings","Pink skin that blanches with pressure","Superficial redness only, similar to sunburn"]'::jsonb, 1, 'Full-thickness burns destroy the epidermis and entire dermis including nerve endings, producing a dry, leathery, often painless (to light touch) appearance that requires grafting.', 'Burns & Trauma', '🔥', true),
(3931, 'Escharotomy', 'AI Practice Question', 'Escharotomy is indicated for a circumferential full-thickness burn of a limb when it:', '["Causes only mild discomfort","Compromises distal circulation, evidenced by diminished pulses or compartment pressure signs","Is less than 24 hours old regardless of circulation","Only affects superficial skin layers"]'::jsonb, 1, 'Circumferential full-thickness burns can act like a tourniquet as tissue swells beneath inelastic eschar; escharotomy relieves this pressure to restore distal circulation.', 'Burns & Trauma', '🔥', true),
(3932, 'Rule of Nines', 'AI Practice Question', 'Using the Rule of Nines, each entire upper limb of an adult represents approximately what percentage of total body surface area?', '["4.5%","9%","18%","36%"]'::jsonb, 1, 'The adult Rule of Nines assigns roughly 9% TBSA to each entire arm, 18% to each leg, 18% to the anterior trunk, 18% to the posterior trunk, and 9% to the head/neck.', 'Burns & Trauma', '🔥', true),
(3933, 'Trauma Primary Survey', 'AI Practice Question', 'The correct sequence of the trauma primary survey (ABCDE) is:', '["Airway, Breathing, Circulation, Disability, Exposure","Exposure, Disability, Circulation, Breathing, Airway","Breathing, Airway, Circulation, Exposure, Disability","Circulation, Airway, Breathing, Disability, Exposure"]'::jsonb, 0, 'The primary survey follows a fixed priority sequence — Airway (with cervical spine control), Breathing, Circulation, Disability (neurological status), and Exposure — to rapidly identify and treat life-threatening injuries.', 'Burns & Trauma', '🔥', true),
(3934, 'Compartment Syndrome', 'AI Practice Question', 'The classic ''5 Ps'' used to assess for compartment syndrome are pain, pallor, paresthesia, pulselessness, and:', '["Pruritus","Paralysis","Palpitations","Polyuria"]'::jsonb, 1, 'The 5 Ps of compartment syndrome are pain (often out of proportion), pallor, paresthesia, pulselessness (a late finding), and paralysis.', 'Burns & Trauma', '🔥', true),
(3935, 'FAST Exam', 'AI Practice Question', 'In a trauma patient, the FAST exam is primarily performed to rapidly detect:', '["Long bone fractures","Free intraperitoneal or pericardial fluid suggestive of haemorrhage","Cervical spine instability","Pneumonia"]'::jsonb, 1, 'FAST uses bedside ultrasound to rapidly detect free fluid, typically blood, in the abdominal, pelvic, and pericardial spaces in trauma patients.', 'Burns & Trauma', '🔥', true),
(3936, 'Injury Severity Score', 'AI Practice Question', 'The Injury Severity Score (ISS) is used to:', '["Determine a patient''s blood type","Quantify overall trauma severity across multiple body regions to help predict outcomes","Replace the need for a primary survey","Measure pain intensity only"]'::jsonb, 1, 'The ISS combines the severity of injuries across different body regions into a single score used to characterise overall trauma severity and predict mortality risk.', 'Burns & Trauma', '🔥', true),
(3937, 'Burns and Inhalation Injury', 'AI Practice Question', 'Carbon monoxide poisoning should be suspected in a burn patient presenting with:', '["Normal mental status and clear lung sounds","Soot around the mouth/nose, singed nasal hairs, and altered mental status","Isolated limb burns only, without facial involvement","Bradycardia alone"]'::jsonb, 1, 'Facial burns, soot in the airway/nares, singed nasal hairs, and altered mentation raise strong suspicion for inhalation injury and carbon monoxide poisoning, requiring high-flow oxygen and further evaluation.', 'Burns & Trauma', '🔥', true),
(3938, 'Burn Fluid Resuscitation Timing', 'AI Practice Question', 'According to the Parkland formula, the first half of the calculated 24-hour fluid volume should be given within:', '["The first hour only","The first 8 hours from the time of injury","The first 16 hours","Evenly over the full 24 hours"]'::jsonb, 1, 'Half of the calculated 24-hour Parkland fluid volume is given during the first 8 hours from the time of injury (not from arrival), with the remaining half over the following 16 hours.', 'Burns & Trauma', '🔥', true),
(3939, 'Tetanus Prophylaxis', 'AI Practice Question', 'Tetanus prophylaxis should be considered for any patient presenting with:', '["A clean, superficial abrasion only in a fully immunised patient","A contaminated or deep wound with uncertain or incomplete immunisation status","Any minor bruise","Only burns, never lacerations"]'::jsonb, 1, 'Tetanus risk assessment depends on both the wound type (especially contaminated or deep wounds) and the patient''s immunisation history, with prophylaxis given accordingly.', 'Burns & Trauma', '🔥', true),
(3940, 'Golden Hour', 'AI Practice Question', 'The ''golden hour'' concept in trauma care refers to:', '["The hour before a shift change","The critical early time period in which prompt intervention significantly improves survival outcomes","A mandatory one-hour observation period before discharge","The hour reserved for documentation"]'::jsonb, 1, 'The golden hour concept emphasises that rapid assessment, resuscitation, and definitive treatment in the early period after major trauma significantly improve patient survival and outcomes.', 'Burns & Trauma', '🔥', true),
(3941, 'DKA Management', 'AI Practice Question', 'In the management of diabetic ketoacidosis, the initial treatment priority is generally:', '["Immediate high-dose insulin bolus before any fluids","Fluid resuscitation, followed by careful insulin therapy and electrolyte monitoring","Oral hypoglycaemic agents","Restricting all fluids"]'::jsonb, 1, 'DKA management begins with fluid resuscitation to address dehydration and improve perfusion, followed by insulin therapy (typically as an infusion) with close monitoring and correction of potassium before/alongside insulin, since insulin drives potassium intracellularly.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3942, 'SIADH vs Diabetes Insipidus', 'AI Practice Question', 'A key distinguishing feature between SIADH and diabetes insipidus is that SIADH causes:', '["Dilute urine and hypernatraemia","Concentrated urine and hyponatraemia due to water retention","Massive polyuria with dilute urine","No change in serum sodium"]'::jsonb, 1, 'SIADH causes excessive water retention, producing concentrated urine (high urine osmolality) with dilutional hyponatraemia, in contrast to diabetes insipidus, which causes dilute polyuria and can cause hypernatraemia.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3943, 'Thyroid Storm', 'AI Practice Question', 'Thyroid storm is a life-threatening condition characterised by:', '["Bradycardia and hypothermia","Severe hyperthermia, tachycardia, and altered mental status from extreme thyroid hormone excess","Normal vital signs with mild fatigue","Hypotension without tachycardia"]'::jsonb, 1, 'Thyroid storm is an extreme, life-threatening exacerbation of hyperthyroidism presenting with high fever, marked tachycardia/arrhythmias, and altered mental status, requiring urgent treatment.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3944, 'Pancreatitis Severity', 'AI Practice Question', 'Ranson''s criteria are used clinically to:', '["Diagnose gallstones","Assess the severity and prognosis of acute pancreatitis","Grade liver cirrhosis","Diagnose peptic ulcer disease"]'::jsonb, 1, 'Ranson''s criteria use a set of clinical and laboratory parameters assessed at admission and at 48 hours to estimate the severity and prognosis of acute pancreatitis.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3945, 'Hepatic Encephalopathy', 'AI Practice Question', 'Lactulose is used in the management of hepatic encephalopathy primarily to:', '["Increase serum ammonia levels","Reduce serum ammonia by promoting its excretion in the stool","Treat variceal bleeding directly","Lower blood glucose"]'::jsonb, 1, 'Lactulose acidifies the colon and acts as an osmotic laxative, trapping ammonia as ammonium and promoting its faecal excretion, thereby reducing the encephalopathy-causing ammonia burden.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3946, 'Upper GI Bleed', 'AI Practice Question', 'Initial priority management of an unstable patient with an acute upper GI bleed includes:', '["Immediate discharge with follow-up","Airway protection, IV access, and fluid/blood resuscitation","Oral intake to dilute stomach acid","Withholding all IV fluids"]'::jsonb, 1, 'Unstable GI bleed management prioritises airway protection (especially with haematemesis or altered consciousness), establishing large-bore IV access, and fluid/blood product resuscitation before definitive endoscopic treatment.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3947, 'Variceal Bleeding', 'AI Practice Question', 'Octreotide (a somatostatin analogue) is used in variceal bleeding to:', '["Increase splanchnic blood flow and portal pressure","Reduce splanchnic blood flow and portal venous pressure, decreasing variceal bleeding","Directly clot the bleeding vessel","Treat hepatic encephalopathy"]'::jsonb, 1, 'Octreotide reduces splanchnic blood flow and portal pressure, helping to reduce bleeding from oesophageal varices while definitive endoscopic treatment is arranged.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3948, 'Addisonian Crisis', 'AI Practice Question', 'The emergency treatment for an acute Addisonian (adrenal) crisis is:', '["High-dose insulin","IV hydrocortisone and aggressive fluid resuscitation","Beta-blockers","Diuretics"]'::jsonb, 1, 'Acute adrenal crisis requires immediate IV hydrocortisone to replace deficient cortisol along with aggressive isotonic fluid resuscitation for the associated hypotension and electrolyte disturbances.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3949, 'Refeeding Syndrome', 'AI Practice Question', 'Refeeding syndrome is a risk primarily in patients who:', '["Have been well-nourished throughout admission","Have experienced prolonged starvation or severe malnutrition before reintroducing nutrition","Are only mildly overweight","Have normal phosphate levels only"]'::jsonb, 1, 'Refeeding syndrome risk is highest in severely malnourished or prolonged-starvation patients, where reintroducing nutrition triggers dangerous shifts in phosphate, potassium, and magnesium as insulin secretion resumes.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3950, 'Enteral Feeding Safety', 'AI Practice Question', 'To reduce aspiration risk during nasogastric tube feeding, the head of bed should be maintained at:', '["Flat, 0 degrees","Elevated 30–45 degrees","Trendelenburg position","Prone position"]'::jsonb, 1, 'Elevating the head of bed 30–45 degrees during and after enteral feeding reduces the risk of gastric reflux and aspiration.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3951, 'Metabolic Syndrome', 'AI Practice Question', 'Metabolic syndrome is characterised by a cluster of findings including:', '["Only elevated blood glucose in isolation","Central obesity, hypertension, dyslipidaemia, and insulin resistance/hyperglycaemia occurring together","Isolated hypothyroidism","Only low blood pressure"]'::jsonb, 1, 'Metabolic syndrome describes the co-occurrence of central obesity, hypertension, dyslipidaemia (high triglycerides/low HDL), and insulin resistance, together increasing cardiovascular and diabetes risk.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3952, 'Nursing Process', 'AI Practice Question', 'The five steps of the nursing process, in order, are:', '["Diagnosis, assessment, planning, implementation, evaluation","Assessment, diagnosis, planning, implementation, evaluation","Planning, assessment, diagnosis, evaluation, implementation","Implementation, planning, assessment, diagnosis, evaluation"]'::jsonb, 1, 'The nursing process (ADPIE) follows the sequence: Assessment, Diagnosis, Planning, Implementation, and Evaluation, providing a systematic framework for individualised patient care.', 'Research & Nursing Process', '📊', true),
(3953, 'PICO Format', 'AI Practice Question', 'In the PICO framework for developing a clinical research question, the letters stand for:', '["Population, Intervention, Comparison, Outcome","Problem, Investigation, Cost, Objective","Patient, Illness, Cure, Observation","Plan, Implement, Coordinate, Overview"]'::jsonb, 0, 'PICO structures a clinical question around Population (or patient), Intervention, Comparison, and Outcome, helping focus literature searches and research design.', 'Research & Nursing Process', '📊', true),
(3954, 'Evidence Hierarchy', 'AI Practice Question', 'In the hierarchy of evidence, which is generally considered the strongest level of evidence?', '["Expert opinion","Case reports","Systematic reviews and meta-analyses of randomised controlled trials","Individual observational studies"]'::jsonb, 2, 'Systematic reviews and meta-analyses that synthesise multiple high-quality randomised controlled trials sit at the top of the evidence hierarchy, above individual studies, case reports, or expert opinion.', 'Research & Nursing Process', '📊', true),
(3955, 'Reliability and Validity', 'AI Practice Question', 'In research methodology, reliability refers to the consistency of a measurement, while validity refers to:', '["The cost of conducting the study","Whether the instrument actually measures what it is intended to measure","The number of participants enrolled","The length of the study"]'::jsonb, 1, 'Reliability concerns consistency/reproducibility of measurement, whereas validity concerns whether the tool truly measures the concept it claims to measure.', 'Research & Nursing Process', '📊', true),
(3956, 'Research Ethics', 'AI Practice Question', 'A core ethical requirement in human subjects research is that participation must be:', '["Mandatory for all eligible patients","Voluntary, based on informed consent, without coercion","Compensated financially regardless of consent","Determined solely by the researcher"]'::jsonb, 1, 'Ethical research requires that participants voluntarily consent to participate after being fully informed, free from coercion or undue influence.', 'Research & Nursing Process', '📊', true),
(3957, 'Qualitative vs Quantitative Research', 'AI Practice Question', 'Qualitative research methods are primarily used to:', '["Generate statistically generalisable numerical data","Explore and understand experiences, meanings, and phenomena in depth","Test drug efficacy through randomised trials","Calculate p-values"]'::jsonb, 1, 'Qualitative research explores subjective experiences, meanings, and context in depth using methods such as interviews and thematic analysis, differing from quantitative research''s numerical, statistical focus.', 'Research & Nursing Process', '📊', true),
(3958, 'Nursing vs Medical Diagnosis', 'AI Practice Question', 'A nursing diagnosis differs from a medical diagnosis in that a nursing diagnosis:', '["Identifies a specific disease process","Describes a patient''s response to actual or potential health problems that nursing care can address","Can only be made by a physician","Requires no assessment data"]'::jsonb, 1, 'Nursing diagnoses (e.g. ''ineffective airway clearance'') describe the patient''s response to a health condition and guide independent nursing interventions, distinct from a medical diagnosis naming a disease.', 'Research & Nursing Process', '📊', true),
(3959, 'Randomisation', 'AI Practice Question', 'Randomisation in a randomised controlled trial primarily serves to:', '["Increase the cost of the study","Reduce selection bias and evenly distribute known and unknown confounding variables between groups","Guarantee a statistically significant result","Eliminate the need for a control group"]'::jsonb, 1, 'Random allocation to study groups helps ensure that both known and unknown confounding factors are evenly distributed, reducing selection bias and strengthening causal inference.', 'Research & Nursing Process', '📊', true),
(3960, 'Statistical Power', 'AI Practice Question', 'Statistical power in a research study refers to the study''s ability to:', '["Guarantee a positive result","Correctly detect a true effect or difference if one actually exists","Eliminate all bias","Reduce the sample size required to zero"]'::jsonb, 1, 'Statistical power is the probability that a study will correctly detect a true effect when one exists, influenced by sample size, effect size, and variability.', 'Research & Nursing Process', '📊', true),
(3961, 'Evidence-Based Practice', 'AI Practice Question', 'The steps of evidence-based practice generally begin with:', '["Implementing a new policy immediately without question","Formulating a clear clinical question, then searching for and critically appraising the best available evidence","Ignoring clinical expertise entirely","Relying solely on tradition"]'::jsonb, 1, 'Evidence-based practice starts with asking a focused clinical question, then systematically searching for, critically appraising, and integrating the best available evidence with clinical expertise and patient values.', 'Research & Nursing Process', '📊', true),
(3962, 'Preeclampsia Management', 'AI Practice Question', 'Magnesium sulfate is administered in severe preeclampsia primarily to:', '["Lower blood glucose","Prevent or treat eclamptic seizures","Induce labour immediately","Treat postpartum haemorrhage"]'::jsonb, 1, 'Magnesium sulfate is the drug of choice for seizure prophylaxis and treatment in severe preeclampsia/eclampsia, requiring monitoring for signs of magnesium toxicity such as loss of deep tendon reflexes and respiratory depression.', 'Obstetric & Neonatal', '🤱', true),
(3963, 'APGAR Score', 'AI Practice Question', 'The APGAR score evaluates a newborn''s condition based on which five components?', '["Appearance, pulse, grimace, activity, and respiration","Airway, pulse, glucose, activity, respiration","Appearance, position, glucose, activity, reflex","Alertness, pain, growth, appetite, reflex"]'::jsonb, 0, 'The APGAR score assesses Appearance (colour), Pulse (heart rate), Grimace (reflex irritability), Activity (muscle tone), and Respiration, each scored 0–2, at 1 and 5 minutes after birth.', 'Obstetric & Neonatal', '🤱', true),
(3964, 'Postpartum Haemorrhage', 'AI Practice Question', 'The ''4 Ts'' framework for causes of postpartum haemorrhage includes tone, tissue, trauma, and:', '["Temperature","Thrombin (coagulopathy)","Tachycardia","Transfusion"]'::jsonb, 1, 'The 4 Ts mnemonic for postpartum haemorrhage causes stands for Tone (uterine atony), Tissue (retained products), Trauma (lacerations), and Thrombin (coagulopathy).', 'Obstetric & Neonatal', '🤱', true),
(3965, 'Placental Abnormalities', 'AI Practice Question', 'A key distinguishing feature between placental abruption and placenta previa is that abruption classically presents with:', '["Painless vaginal bleeding","Painful vaginal bleeding, often with a rigid, tender uterus","No vaginal bleeding at all","Bleeding only in the first trimester"]'::jsonb, 1, 'Placental abruption typically causes painful bleeding with uterine tenderness/rigidity, whereas placenta previa classically causes painless bright red vaginal bleeding.', 'Obstetric & Neonatal', '🤱', true),
(3966, 'Neonatal Resuscitation', 'AI Practice Question', 'The initial steps of neonatal resuscitation for a newly born infant include:', '["Immediate intubation of every newborn","Providing warmth, positioning the airway, drying, and stimulating the infant","Immediate chest compressions regardless of heart rate","Delaying any assessment for 5 minutes"]'::jsonb, 1, 'Initial neonatal resuscitation steps focus on providing warmth, opening the airway, drying, and tactile stimulation, before further interventions are escalated based on ongoing assessment of breathing and heart rate.', 'Obstetric & Neonatal', '🤱', true),
(3967, 'Preeclampsia Diagnosis', 'AI Practice Question', 'Preeclampsia is generally diagnosed by new-onset hypertension after 20 weeks gestation together with:', '["Isolated mild headache only","Proteinuria or other signs of end-organ dysfunction","Normal blood pressure readings","Glucose intolerance alone"]'::jsonb, 1, 'Preeclampsia diagnosis requires new-onset hypertension after 20 weeks gestation accompanied by proteinuria or other evidence of maternal end-organ involvement (e.g. renal, hepatic, neurological, or haematological dysfunction).', 'Obstetric & Neonatal', '🤱', true),
(3968, 'HELLP Syndrome', 'AI Practice Question', 'HELLP syndrome, a severe variant of preeclampsia, is characterised by:', '["Hypertension only, with normal laboratory values","Haemolysis, Elevated Liver enzymes, and Low Platelets","Hyperglycaemia, Elevated lipids, Low leukocytes, Proteinuria","Normal coagulation studies"]'::jsonb, 1, 'HELLP syndrome stands for Haemolysis, Elevated Liver enzymes, and Low Platelet count, representing a severe, potentially life-threatening complication of preeclampsia.', 'Obstetric & Neonatal', '🤱', true),
(3969, 'Umbilical Cord Prolapse', 'AI Practice Question', 'Umbilical cord prolapse is an obstetric emergency because it can cause:', '["Improved fetal oxygenation","Cord compression leading to fetal hypoxia","Maternal hypertension only","No risk if the mother is asymptomatic"]'::jsonb, 1, 'When the umbilical cord prolapses ahead of the presenting fetal part, it can become compressed, acutely compromising fetal blood flow and oxygenation, requiring emergency intervention.', 'Obstetric & Neonatal', '🤱', true),
(3970, 'Neonatal Hypoglycaemia', 'AI Practice Question', 'Neonates at increased risk for hypoglycaemia after birth include those born to:', '["Mothers with well-controlled, non-diabetic pregnancies","Diabetic mothers, and infants who are preterm or growth-restricted","Mothers with normal glucose tolerance only","Only infants born after 42 weeks gestation"]'::jsonb, 1, 'Infants of diabetic mothers, preterm infants, and growth-restricted infants have higher risk of neonatal hypoglycaemia due to altered glucose regulation and reduced glycogen stores.', 'Obstetric & Neonatal', '🤱', true),
(3971, 'Amniotic Fluid Embolism', 'AI Practice Question', 'Amniotic fluid embolism classically presents with the sudden onset of:', '["Gradual, mild shortness of breath over days","Acute hypoxia, hypotension, and coagulopathy during or shortly after labour","Isolated mild fever","Chronic hypertension"]'::jsonb, 1, 'Amniotic fluid embolism is a rare but catastrophic event presenting with sudden cardiorespiratory collapse, hypoxia, hypotension, and disseminated intravascular coagulation during or shortly after labour/delivery.', 'Obstetric & Neonatal', '🤱', true),
(3972, 'Glasgow Coma Scale', 'AI Practice Question', 'The Glasgow Coma Scale evaluates a patient across which three components?', '["Pulse, blood pressure, temperature","Eye opening, verbal response, and motor response","Pupil size, reflexes, and strength","Respiratory rate, oxygen saturation, and heart rate"]'::jsonb, 1, 'The GCS scores eye opening (1–4), verbal response (1–5), and motor response (1–6), summed to a total score reflecting level of consciousness.', 'Neurology', '🧠', true),
(3973, 'Cushing''s Triad', 'AI Practice Question', 'Cushing''s triad, a late sign of raised intracranial pressure, consists of:', '["Hypotension, tachycardia, and tachypnoea","Hypertension, bradycardia, and irregular respirations","Hypotension, bradycardia, and regular respirations","Normal vital signs with confusion"]'::jsonb, 1, 'Cushing''s triad — widened pulse pressure/hypertension, bradycardia, and irregular respiratory pattern — reflects the body''s response to significantly raised intracranial pressure and impending herniation, a late and ominous sign.', 'Neurology', '🧠', true),
(3974, 'ICP Management', 'AI Practice Question', 'Positioning the head of bed at 30 degrees in a patient with raised intracranial pressure helps to:', '["Increase ICP further","Promote venous drainage from the brain and help lower ICP","Have no effect on cerebral perfusion","Replace the need for other ICP-lowering measures"]'::jsonb, 1, 'Elevating the head of bed to about 30 degrees (with the head in neutral alignment) promotes venous outflow from the brain, helping to reduce intracranial pressure.', 'Neurology', '🧠', true),
(3975, 'Status Epilepticus', 'AI Practice Question', 'First-line pharmacological treatment for status epilepticus is typically:', '["Phenytoin as the very first drug given","A benzodiazepine, such as IV lorazepam or diazepam","Aspirin","Insulin"]'::jsonb, 1, 'Benzodiazepines are the recommended first-line treatment to rapidly terminate prolonged or repeated seizures in status epilepticus, with second-line agents like phenytoin used if seizures persist.', 'Neurology', '🧠', true),
(3976, 'Stroke Classification', 'AI Practice Question', 'The key initial investigation to differentiate ischaemic from haemorrhagic stroke is:', '["Lumbar puncture","Non-contrast CT head","Chest X-ray","ECG"]'::jsonb, 1, 'A non-contrast CT head is performed urgently to distinguish ischaemic stroke from haemorrhagic stroke, a critical distinction since thrombolysis is contraindicated in haemorrhage.', 'Neurology', '🧠', true),
(3977, 'Thrombolysis in Stroke', 'AI Practice Question', 'Intravenous tissue plasminogen activator (tPA) for acute ischaemic stroke is generally most effective when given within approximately:', '["24 hours of symptom onset with no time constraint","4.5 hours of symptom onset, in eligible patients","72 hours of symptom onset","1 week of symptom onset"]'::jsonb, 1, 'IV tPA for eligible acute ischaemic stroke patients is generally administered within a narrow time window, commonly cited as up to 4.5 hours from clearly defined symptom onset, after excluding contraindications such as haemorrhage.', 'Neurology', '🧠', true),
(3978, 'Brain Death', 'AI Practice Question', 'Determination of brain death requires demonstrating:', '["Temporary unresponsiveness that improves with stimulation","Irreversible absence of all brainstem reflexes and cessation of brain function, per established clinical criteria","A single abnormal EEG reading alone","Low blood pressure only"]'::jsonb, 1, 'Brain death determination follows strict clinical criteria confirming the complete and irreversible absence of brain and brainstem function, typically including apnoea testing and absent brainstem reflexes.', 'Neurology', '🧠', true),
(3979, 'Autonomic Dysreflexia', 'AI Practice Question', 'Autonomic dysreflexia in a patient with a spinal cord injury above T6 is typically triggered by:', '["A noxious stimulus below the level of injury, such as a distended bladder","Mild anxiety only","Normal ambient room temperature","Eating a regular meal"]'::jsonb, 0, 'Autonomic dysreflexia is triggered by a noxious stimulus below the injury level (commonly bladder distension or bowel impaction), causing a dangerous, uncontrolled sympathetic surge and severe hypertension in patients with cord injury above T6.', 'Neurology', '🧠', true),
(3980, 'Brain Herniation', 'AI Practice Question', 'A unilaterally dilated, non-reactive (''blown'') pupil in a patient with a head injury is a concerning sign of:', '["Normal pupillary variation","Uncal/transtentorial herniation compressing the oculomotor nerve","Improved neurological status","Peripheral nerve injury unrelated to the brain"]'::jsonb, 1, 'A unilaterally dilated, fixed pupil suggests compression of the oculomotor (third cranial) nerve, classically from uncal herniation, and is a neurosurgical emergency.', 'Neurology', '🧠', true),
(3981, 'Pupillary Assessment', 'AI Practice Question', 'Bilaterally pinpoint pupils in an unresponsive patient may suggest:', '["Opioid toxicity or a pontine lesion","Anticholinergic drug effect","Normal resting pupil size in bright light only","Complete brain death in all cases"]'::jsonb, 0, 'Bilateral pinpoint pupils are classically associated with opioid toxicity or a pontine brainstem lesion, both of which can also cause depressed respiratory drive.', 'Neurology', '🧠', true),
(3982, 'STEMI ECG Changes', 'AI Practice Question', 'ST-segment elevation in leads II, III, and aVF is most consistent with a myocardial infarction affecting the:', '["Anterior wall","Inferior wall","Lateral wall","Posterior wall exclusively"]'::jsonb, 1, 'Leads II, III, and aVF view the inferior surface of the heart, so ST elevation here indicates an inferior wall myocardial infarction, typically from right coronary artery occlusion.', 'Cardiovascular', '🫀', true),
(3983, 'Cardiac Tamponade', 'AI Practice Question', 'Beck''s triad, associated with cardiac tamponade, consists of hypotension, muffled heart sounds, and:', '["Bradycardia","Jugular venous distension","Polyuria","Hyperthermia"]'::jsonb, 1, 'Beck''s triad — hypotension, muffled/distant heart sounds, and jugular venous distension — reflects the impaired cardiac filling and output caused by pericardial fluid compressing the heart in tamponade.', 'Cardiovascular', '🫀', true),
(3984, 'Pulsus Paradoxus', 'AI Practice Question', 'Pulsus paradoxus, associated with cardiac tamponade, is defined as:', '["An abnormal rise in systolic blood pressure during inspiration","An exaggerated fall (greater than 10mmHg) in systolic blood pressure during inspiration","A completely irregular pulse rhythm","Absence of a palpable pulse"]'::jsonb, 1, 'Pulsus paradoxus is an exaggerated decrease in systolic blood pressure of more than 10mmHg during inspiration, reflecting impaired ventricular filling from external compression, as in cardiac tamponade.', 'Cardiovascular', '🫀', true),
(3985, 'Heart Failure Biomarkers', 'AI Practice Question', 'An elevated B-type natriuretic peptide (BNP) level is most useful clinically to help:', '["Diagnose myocardial infarction specifically","Support the diagnosis of heart failure and assess its severity","Diagnose pulmonary embolism definitively","Measure renal clearance directly"]'::jsonb, 1, 'BNP is released from stretched ventricular myocardium under volume/pressure overload, and elevated levels support a diagnosis of heart failure, correlating broadly with severity.', 'Cardiovascular', '🫀', true),
(3986, 'Pacemaker Modes', 'AI Practice Question', 'In pacemaker coding, a DDD mode means the device paces and senses in:', '["The atrium only","Both the atrium and ventricle, with dual response modes","The ventricle only, with no sensing","Neither chamber"]'::jsonb, 1, 'DDD mode pacemakers pace and sense in both the atrium and ventricle (Dual, Dual), with a Dual response (both triggered and inhibited) based on sensed activity, providing more physiological pacing.', 'Cardiovascular', '🫀', true),
(3987, 'Post-CABG Care', 'AI Practice Question', 'Chest tube drainage exceeding approximately 200–300mL per hour after coronary artery bypass surgery should prompt concern for:', '["Normal expected postoperative drainage","Postoperative haemorrhage requiring urgent evaluation","Chest tube malfunction only, with no clinical significance","Resolution of the surgical procedure"]'::jsonb, 1, 'Chest tube output consistently exceeding roughly 200–300mL/hour (or specific institutional thresholds) after cardiac surgery raises concern for significant postoperative bleeding and may require surgical re-exploration.', 'Cardiovascular', '🫀', true),
(3988, 'Atrial Fibrillation', 'AI Practice Question', 'The CHA2DS2-VASc score is used in atrial fibrillation to assess:', '["Bleeding risk from anticoagulation","Stroke risk, guiding the decision for anticoagulation therapy","Rate control medication dosing","Cardioversion energy requirements"]'::jsonb, 1, 'The CHA2DS2-VASc score estimates a patient''s stroke risk in non-valvular atrial fibrillation, guiding decisions about whether anticoagulation is warranted.', 'Cardiovascular', '🫀', true),
(3989, 'Cardiogenic Pulmonary Oedema', 'AI Practice Question', 'Priority management of acute cardiogenic pulmonary oedema typically includes:', '["Aggressive fluid boluses","Oxygen therapy, diuretics, and reducing preload/afterload as appropriate","Withholding all oxygen","Immediate large-volume crystalloid infusion"]'::jsonb, 1, 'Management of cardiogenic pulmonary oedema focuses on improving oxygenation, reducing preload with diuretics/vasodilators as appropriate, and supporting ventilation, rather than administering additional fluid.', 'Cardiovascular', '🫀', true),
(3990, 'Cardiac Tamponade Management', 'AI Practice Question', 'Definitive emergency treatment for haemodynamically significant cardiac tamponade is:', '["Oral diuretics","Pericardiocentesis to drain the pericardial fluid","Beta-blockers","Aggressive fluid restriction alone"]'::jsonb, 1, 'Pericardiocentesis (or surgical drainage) to remove the compressing pericardial fluid is the definitive emergency treatment for tamponade causing haemodynamic compromise.', 'Cardiovascular', '🫀', true),
(3991, 'Torsades de Pointes', 'AI Practice Question', 'Torsades de pointes, a polymorphic ventricular tachycardia, is classically associated with:', '["A shortened QT interval","A prolonged QT interval","Normal QT interval in all cases","Complete heart block only"]'::jsonb, 1, 'Torsades de pointes arises in the setting of a prolonged QT interval (congenital or drug-induced), and IV magnesium sulfate is a key treatment regardless of magnesium level.', 'Cardiovascular', '🫀', true),
(3992, 'Vital Parameters', 'AI Practice Question', 'Normal intracranial pressure in an adult is generally considered to be:', '["0–15 mmHg","30–40 mmHg","50–60 mmHg","Above 25 mmHg at baseline"]'::jsonb, 0, 'Normal ICP in adults is typically cited as roughly 0–15mmHg; sustained pressures above about 20mmHg are generally considered pathological and require intervention.', 'Mixed Revision', '📚', true),
(3993, 'Vital Parameters', 'AI Practice Question', 'Normal central venous pressure (CVP) is generally in the range of:', '["2–8 mmHg","20–30 mmHg","40–50 mmHg","Below 0 mmHg"]'::jsonb, 0, 'Normal CVP is typically cited as approximately 2–8mmHg, reflecting right atrial filling pressure and used as one indicator (among others) of volume status.', 'Mixed Revision', '📚', true),
(3994, 'Glasgow Coma Scale', 'AI Practice Question', 'The lowest and highest possible total scores on the Glasgow Coma Scale are:', '["1 and 10","3 and 15","0 and 20","5 and 25"]'::jsonb, 1, 'The GCS ranges from a minimum of 3 (deep coma/unresponsive) to a maximum of 15 (fully alert and oriented).', 'Mixed Revision', '📚', true),
(3995, 'Urine Output', 'AI Practice Question', 'Adequate adult urine output is generally considered to be at least:', '["0.5 mL/kg/hr","5 mL/kg/hr","10 mL/kg/hr","0.05 mL/kg/hr"]'::jsonb, 0, 'A minimum urine output of about 0.5 mL/kg/hr is generally used as the threshold for adequate renal perfusion in adults; output below this defines oliguria.', 'Mixed Revision', '📚', true),
(3996, 'Sepsis Definitions', 'AI Practice Question', 'Sepsis is currently defined (Sepsis-3) as:', '["Any infection, regardless of organ function","Life-threatening organ dysfunction caused by a dysregulated host response to infection","A fever above 38°C alone","Bacteraemia without any clinical symptoms"]'::jsonb, 1, 'The Sepsis-3 definition characterises sepsis as life-threatening organ dysfunction resulting from a dysregulated host response to infection, typically identified using a significant change in SOFA score.', 'Mixed Revision', '📚', true),
(3997, 'SIRS Criteria', 'AI Practice Question', 'Systemic Inflammatory Response Syndrome (SIRS) criteria include abnormalities in temperature, heart rate, respiratory rate, and:', '["Blood pressure only","White blood cell count","Serum sodium only","Urine output only"]'::jsonb, 1, 'SIRS criteria traditionally include abnormal temperature, heart rate, respiratory rate/PaCO2, and white blood cell count, with two or more abnormal parameters meeting the definition.', 'Mixed Revision', '📚', true),
(3998, 'Arterial Blood Gas Normal Values', 'AI Practice Question', 'Normal arterial blood pH is approximately:', '["6.8–7.0","7.35–7.45","7.6–7.8","8.0–8.5"]'::jsonb, 1, 'Normal arterial pH falls within the narrow range of approximately 7.35–7.45, with values outside this range representing acidosis or alkalosis.', 'Mixed Revision', '📚', true),
(3999, 'Oxygen Therapy Targets', 'AI Practice Question', 'In a patient with chronic COPD and risk of CO2 retention, a commonly recommended SpO2 target range is:', '["100% at all times","Approximately 88–92%","Below 80%","Exactly 95–100%, matching healthy adults"]'::jsonb, 1, 'In COPD patients at risk of hypercapnic respiratory failure, a more conservative SpO2 target of roughly 88–92% is often recommended to avoid suppressing hypoxic respiratory drive and worsening CO2 retention.', 'Mixed Revision', '📚', true),
(4000, 'ARDS Ventilation Strategy', 'AI Practice Question', 'The ARDSnet protocol recommends a low tidal volume ventilation strategy of approximately:', '["12–15 mL/kg ideal body weight","6 mL/kg ideal body weight","20 mL/kg ideal body weight","2 mL/kg ideal body weight"]'::jsonb, 1, 'Lung-protective ventilation in ARDS uses a low tidal volume of approximately 6mL/kg ideal (predicted) body weight to reduce ventilator-induced lung injury from overdistension.', 'Respiratory', '🫁', true),
(4001, 'PEEP', 'AI Practice Question', 'Positive end-expiratory pressure (PEEP) is applied during mechanical ventilation primarily to:', '["Increase the risk of alveolar collapse","Keep alveoli open at end-expiration, improving oxygenation and functional residual capacity","Lower mean airway pressure","Eliminate the need for FiO2 titration"]'::jsonb, 1, 'PEEP maintains positive pressure in the airways at the end of expiration, preventing alveolar collapse (atelectasis) and improving oxygenation by increasing functional residual capacity.', 'Respiratory', '🫁', true),
(4002, 'Ventilator Weaning', 'AI Practice Question', 'The Rapid Shallow Breathing Index (RSBI) is used to help predict:', '["Optimal PEEP setting","Readiness for ventilator weaning/extubation","The need for intubation","Correct ETT size"]'::jsonb, 1, 'RSBI (respiratory rate divided by tidal volume in litres) below approximately 105 is commonly used as a predictor of successful weaning from mechanical ventilation.', 'Respiratory', '🫁', true),
(4003, 'Chest Tube Management', 'AI Practice Question', 'Continuous bubbling in the water seal chamber of a chest drainage system suggests:', '["Normal, expected fluctuation with respiration","An air leak in the system or from the pleural space","The chest tube has been successfully removed","Overdrainage of pleural fluid"]'::jsonb, 1, 'Continuous (rather than intermittent, respiration-related) bubbling in the water seal chamber suggests an air leak, either from the pleural space (persistent pneumothorax) or a loose connection in the drainage system.', 'Respiratory', '🫁', true),
(4004, 'Auto-PEEP', 'AI Practice Question', 'Auto-PEEP (breath stacking) occurs when:', '["The patient fully exhales before the next breath is delivered","Insufficient expiratory time prevents complete exhalation before the next breath, trapping air","PEEP is set too low","The ventilator circuit has no leaks"]'::jsonb, 1, 'Auto-PEEP develops when the set respiratory rate or expiratory time doesn''t allow complete exhalation, causing progressive air trapping and unintended positive pressure at end-expiration.', 'Respiratory', '🫁', true),
(4005, 'Prone Positioning', 'AI Practice Question', 'Prone positioning in patients with severe ARDS is used because it can:', '["Worsen oxygenation in most patients","Improve ventilation-perfusion matching and oxygenation by recruiting dorsal lung regions","Replace the need for mechanical ventilation","Only benefit haemodynamics, not oxygenation"]'::jsonb, 1, 'Prone positioning redistributes ventilation to previously dependent dorsal lung regions and improves ventilation-perfusion matching, improving oxygenation in many patients with severe ARDS.', 'Respiratory', '🫁', true),
(4006, 'Ventilator Modes', 'AI Practice Question', 'In SIMV (Synchronized Intermittent Mandatory Ventilation) mode, compared to Assist-Control, the patient:', '["Receives full ventilator support for every single breath","Can take spontaneous breaths between mandatory synchronized breaths, at their own tidal volume","Cannot breathe spontaneously at all","Is always fully paralysed"]'::jsonb, 1, 'SIMV delivers a set number of synchronized mandatory breaths while allowing the patient to breathe spontaneously (often with pressure support) between them, unlike Assist-Control, which fully supports every breath the patient triggers.', 'Respiratory', '🫁', true),
(4007, 'Extubation Criteria', 'AI Practice Question', 'Before extubation, a patient should generally demonstrate:', '["Ongoing heavy sedation and inability to protect the airway","Adequate oxygenation, stable haemodynamics, intact airway reflexes, and successful spontaneous breathing trial","A persistently high FiO2 and PEEP requirement","Absence of a cough or gag reflex"]'::jsonb, 1, 'Safe extubation criteria typically include adequate oxygenation on minimal ventilator support, haemodynamic stability, intact airway protective reflexes, and successful completion of a spontaneous breathing trial.', 'Respiratory', '🫁', true),
(4008, 'OSCE: BLS / CPR', 'AI Practice Question', 'Before beginning any OSCE procedure station, the candidate''s first action should generally be to:', '["Start the procedure immediately to save time","Perform hand hygiene and confirm patient identity/consent, explaining the procedure","Skip introductions to move faster","Put on sterile gloves before assessing the scenario"]'::jsonb, 1, 'Examiners consistently mark for hand hygiene, patient identification, and explanation/consent as the standard opening sequence before any clinical procedure, including OSCE stations.', 'OSCE Practice', '🩺', true),
(4009, 'OSCE: IV Cannulation', 'AI Practice Question', 'For rapid fluid resuscitation in an emergency, the most appropriate IV cannula gauge is generally:', '["24G (yellow)","22G (blue)","14–16G (orange/grey)","26G (violet)"]'::jsonb, 2, 'Larger-bore cannulas (14–16G) allow much faster fluid/blood administration and are preferred for emergency resuscitation, whereas smaller gauges (22–24G) suit slower infusions or fragile veins.', 'OSCE Practice', '🩺', true),
(4010, 'OSCE: Suctioning', 'AI Practice Question', 'The Yankauer sucker is primarily used for:', '["Deep endotracheal suctioning","Oropharyngeal suctioning of secretions, blood, or vomit","Nasogastric feeding","Central line flushing"]'::jsonb, 1, 'The rigid Yankauer sucker is designed for suctioning the mouth and oropharynx of secretions, blood, or vomitus, and is not used for deep tracheal suctioning.', 'OSCE Practice', '🩺', true),
(4011, 'OSCE: BVM Ventilation', 'AI Practice Question', 'Correct technique for a single-rescuer bag-valve-mask seal uses the:', '["Whole-hand grip with no thumb involvement","E-C clamp technique, forming a C over the mask and E along the jaw","Two fingers only, with no jaw support","Mask held loosely without a seal"]'::jsonb, 1, 'The E-C clamp technique uses the thumb and index finger forming a ''C'' to seal the mask while the remaining fingers form an ''E'' lifting the jaw, achieving an effective mask seal and open airway.', 'OSCE Practice', '🩺', true),
(4012, 'OSCE: AED Use', 'AI Practice Question', 'Correct AED pad placement for adult defibrillation is:', '["Both pads on the left side of the chest only","One pad below the right clavicle, the other on the left mid-axillary line below the axilla","Both pads on the back only","Directly over the sternum with no lateral placement"]'::jsonb, 1, 'Standard anterolateral pad placement puts one pad below the right clavicle and the other over the left lower ribs at the mid-axillary line, positioning the shock vector across the heart.', 'OSCE Practice', '🩺', true),
(4013, 'OSCE: Central Line Care', 'AI Practice Question', 'During central line dressing changes, strict sterile technique is essential primarily to:', '["Speed up the procedure","Prevent introduction of pathogens and reduce CLABSI risk","Reduce documentation requirements","Avoid the need for hand hygiene"]'::jsonb, 1, 'Sterile technique during central line care minimises the risk of introducing pathogens at the insertion site, directly reducing the risk of central line-associated bloodstream infection.', 'OSCE Practice', '🩺', true),
(4014, 'OSCE: Syringe Pump', 'AI Practice Question', 'Before connecting a prepared syringe to a syringe pump and starting an infusion, the nurse should first:', '["Skip priming to save time","Prime the line to remove air and confirm correct pump settings against the prescription","Disconnect the patient''s existing IV access","Administer the drug as a rapid bolus first"]'::jsonb, 1, 'Priming the line to expel air and independently double-checking the pump rate/dose settings against the prescription are essential safety checks before starting a syringe pump infusion.', 'OSCE Practice', '🩺', true),
(4015, 'OSCE: Tracheostomy Care', 'AI Practice Question', 'The inner cannula of a tracheostomy tube is typically cleaned or changed at a frequency of approximately:', '["Once a month","Every 8 hours, or per institutional protocol/as needed","Only when the tube is first inserted","Once a year"]'::jsonb, 1, 'The inner cannula is commonly cleaned or replaced roughly every 8 hours or per unit protocol/patient need, to reduce secretion buildup and infection risk while the outer cannula generally remains in place longer.', 'OSCE Practice', '🩺', true),
(4016, 'OSCE: OPA Insertion', 'AI Practice Question', 'Correct sizing of an oropharyngeal airway (OPA) is estimated by measuring from the:', '["Tip of the nose to the earlobe","Corner of the mouth to the angle of the jaw (or earlobe)","Chin to the sternal notch","Forehead to the chin"]'::jsonb, 1, 'OPA size is estimated by measuring from the corner of the patient''s mouth to the angle of the jaw or the earlobe, helping select a device that matches airway anatomy.', 'OSCE Practice', '🩺', true),
(4017, 'OSCE: Peak Flow Technique', 'AI Practice Question', 'When performing peak expiratory flow rate (PEFR) measurement, the patient should be instructed to:', '["Sit slouched and breathe normally into the device","Stand or sit upright, take a full deep breath in, seal lips around the mouthpiece, and blow out as hard and fast as possible","Take a slow, gentle breath out","Breathe through the nose only"]'::jsonb, 1, 'Correct PEFR technique requires an upright position, maximal inspiration, a tight lip seal around the mouthpiece, and a single forceful, fast exhalation to obtain an accurate peak flow reading.', 'OSCE Practice', '🩺', true),
(4018, 'OSCE: Oxygen Therapy', 'AI Practice Question', 'The maximum recommended flow rate for a standard nasal cannula is approximately:', '["1 L/min","6 L/min","15 L/min","No upper limit"]'::jsonb, 1, 'Standard nasal cannulas are generally limited to about 6L/min (delivering roughly up to 44% FiO2); higher flows cause mucosal drying and discomfort without proportionally improving oxygen delivery, and a different device is used instead.', 'OSCE Practice', '🩺', true),
(4019, 'OSCE: Pain Assessment', 'AI Practice Question', 'The PQRST mnemonic used in structured pain assessment stands for Provocation/Palliation, Quality, Region/Radiation, Severity, and:', '["Sound","Timing","Sedation","Symmetry"]'::jsonb, 1, 'PQRST guides a systematic pain assessment: Provocation/Palliation, Quality, Region/Radiation, Severity, and Timing (onset, duration, pattern).', 'OSCE Practice', '🩺', true),
(4020, 'OSCE: Pressure Ulcer Prevention', 'AI Practice Question', 'The Braden Scale is used clinically to:', '["Measure blood pressure trends","Assess a patient''s risk of developing a pressure ulcer","Score level of consciousness","Grade burn severity"]'::jsonb, 1, 'The Braden Scale assesses risk factors such as sensory perception, moisture, activity, mobility, nutrition, and friction/shear to stratify a patient''s pressure ulcer risk and guide preventive care.', 'OSCE Practice', '🩺', true),
(4021, 'OSCE: ETT Cuff Management', 'AI Practice Question', 'Endotracheal tube cuff pressure should generally be maintained within approximately:', '["5–10 cmH2O","20–30 cmH2O","60–80 cmH2O","100–120 cmH2O"]'::jsonb, 1, 'Maintaining ETT cuff pressure at roughly 20–30 cmH2O provides an adequate seal to prevent aspiration and air leak while minimising the risk of tracheal mucosal ischaemia from excessive pressure.', 'OSCE Practice', '🩺', true),
(4022, 'OSCE: Airway Equipment', 'AI Practice Question', 'The two main laryngoscope blade types used for intubation are the curved Macintosh and the straight:', '["Yankauer blade","Miller blade","Guedel blade","Magill blade"]'::jsonb, 1, 'The curved Macintosh blade and the straight Miller blade are the two classic laryngoscope blade designs, each with different techniques for exposing the vocal cords during intubation.', 'OSCE Practice', '🩺', true),
(4023, 'OSCE: ETT Suctioning', 'AI Practice Question', 'Recommended suction pressure when performing adult endotracheal tube suctioning is approximately:', '["300–400 mmHg","100–150 mmHg","500–600 mmHg","No pressure limit is needed"]'::jsonb, 1, 'Adult ETT suctioning is typically performed at approximately 100–150mmHg negative pressure, balancing effective secretion removal against the risk of mucosal trauma and hypoxia.', 'OSCE Practice', '🩺', true),
(4024, 'OSCE: Central Line Placement', 'AI Practice Question', 'Following non-emergency central line insertion, correct catheter tip placement is typically confirmed by:', '["Auscultation alone","Chest X-ray before the line is used for infusion (except in emergencies)","Palpation of the insertion site only","The patient''s subjective report of comfort"]'::jsonb, 1, 'A post-insertion chest X-ray is the standard method to confirm correct catheter tip position and exclude complications such as pneumothorax before the line is used for non-emergency infusions.', 'OSCE Practice', '🩺', true),
(4025, 'OSCE: Defibrillation Safety', 'AI Practice Question', 'Immediately before delivering a shock during defibrillation, the operator must:', '["Continue chest compressions throughout the shock","Visually confirm all personnel are clear of the patient and bed","Remove the patient''s ECG leads","Increase the oxygen flow rate directly over the chest"]'::jsonb, 1, 'The operator must call out and visually confirm that no one is in contact with the patient or bed immediately before delivering a shock, preventing inadvertent shock to rescuers.', 'OSCE Practice', '🩺', true),
(4026, 'OSCE: IV Cannula Complications', 'AI Practice Question', 'Signs suggestive of IV cannula infiltration include:', '["Warmth and redness tracking up the vein","Swelling, coolness, and pain at the insertion site with sluggish or absent blood return","Rapid, unimpeded flow with no symptoms","A strong, easily palpable pulse at the site"]'::jsonb, 1, 'Infiltration (fluid leaking into surrounding tissue) typically presents with swelling, coolness, pain, and blanching around the site, along with reduced or absent blood return on aspiration — distinct from the warmth/redness pattern of phlebitis or the tracking pattern of a local infection.', 'OSCE Practice', '🩺', true),
(4027, 'OSCE: Documentation', 'AI Practice Question', 'After completing any OSCE-assessed clinical procedure, the candidate should ensure documentation includes:', '["Only the time the procedure started","The procedure performed, patient response, any complications, and the practitioner''s identity/signature","No documentation is required if the patient is stable","Only the equipment brand used"]'::jsonb, 1, 'Complete procedural documentation records what was done, the patient''s response, any complications encountered, and who performed it — a core competency assessed alongside technical skill in OSCE stations.', 'OSCE Practice', '🩺', true);
